window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]=window.__LIBQ["the-gioi-hoan-my"]["q03"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]["cotTruyen"]=[{"chuong":201,"tieuDe":"Vô Đề","tomTat":"Đêm trăng bên hồ Thạch thôn, Nhóc Tỳ dùng rượu Hầu Nhi cùng phương pháp cổ trong Nguyên Thủy Chân Giải vỗ hòa tan dược lực, trị dứt ám tật kín lâu năm cho tộc trưởng Thạch Vân Phong — một luồng tro bụi phun ra từ miệng lão, lão phục hồi mạnh mẽ như trẻ lại hai mươi tuổi, hé lộ năm đó hơn mười huynh đệ chỉ mình lão sống sót trở về mà mắc bệnh kỳ dị. Nhóc Tỳ tặng thôn dân hơn mười kiện bảo cụ chiến lợi phẩm, gồm kiếm đỏ luyện từ răng nanh Phì Di và sừng thú đoạt từ đệ tử Võ Vương phủ, rồi cùng Thanh Phong trồng cây đào tiên và Ngân Đào thụ chuẩn Thánh dược giữa thôn, vùi bùn cát vàng kim nuôi dưỡng. Sáng hôm sau con Bát Trân Kê thành tinh sổng khỏi túi Càn Khôn, biết độn thổ; Hổ thẩm đòi hầm gà nhưng Nhóc Tỳ ngăn cản vì trứng nó sánh linh dược, cả Thạch quốc chỉ hoàng thất mới có một con. Con gà nằm lười dưới gốc liễu, quỳ lạy thần thụ và coi thường Đại Hồng Điểu. Sau đó Nhóc Tỳ khổ sở vì tháp nhỏ trắng nuốt huyết nhục bảo dược thuần huyết mà không nhả, tự cắn lẫn nhờ Bóng Lông cắn đều vô hiệu, cuối cùng phải nhờ Liễu Thần xem giúp. Liễu Thần trịnh trọng định giá tháp này xuất hiện từ thời Thái Cổ, hiển hóa cả thời Thượng Cổ, có thần uy cái thế."},{"chuong":202,"tieuDe":"Thuần Huyết","tomTat":"Nhóc Tỳ kinh ngạc trước địa vị của Tiểu Tháp và gạn hỏi Liễu Thần về lai lịch cùng thời đại của nó, nhưng bị cảnh cáo không nên dò xét đến cùng kẻo gặp đại họa sát thân, chỉ cần biết đó là bảo cụ thần uy cái thế. Liễu Thần tiết lộ Tiểu Tháp thiếu vài tầng so với nguyên bản, hiện chỉ còn bốn tầng và đang tự chữa trị bằng cách hấp thụ tinh hoa huyết nhục sinh linh. Đòi lại huyết nhục Thôn Thiên Tước và Cùng Kỳ bị Tiểu Tháp nuốt, Nhóc Tỳ chứng kiến Liễu Thần điều khiển Tiểu Tháp nhả ra bột xương vô giá cùng các khối huyết nhục mấy ngàn cân, rồi dùng cành liễu luyện hóa bốn khối huyết nhục thuần huyết thành bốn giọt thần dịch cô đặc quý hơn hơn mười thái cổ di chủng. Bốn giọt thần dịch được chuẩn bị cho việc tẩy lễ mà Liễu Thần từng hứa với Hùng Hài Tử; huyết nhục thừa được Đại Hồng Điểu và Nhị Ngốc Tử vác đi làm tiệc. Sau đó Nhóc Tỳ khổ luyện thân thể mỗi ngày, vác tảng đá hơn mười vạn cân chạy làm mặt đất vỡ toác và nhảy giẫm nát các đỉnh núi, khiến thợ săn Thạch Thôn và Đại Hồng Điểu kinh sợ. Cuối cùng, khi hai năm trôi qua và cửa Hư Thần Giới mở lại, Liễu Thần dùng cành liễu xuyên thủng bầu trời mở lối, Nhóc Tỳ hân hoan tiến vào một khu phế tích để trở lại nơi từng bị đuổi ra."},{"chuong":203,"tieuDe":"Trở Lại Hư Thần Giới","tomTat":"Sau hai năm lẻ một tháng hết hạn cấm cửa, Nhóc Tỳ băng qua thái cổ thần sơn đổ nát rồi dùng thông đạo màu vàng dịch chuyển về Sơ Thủy Địa, ngồi xổm trên tảng đá xanh cũ khảm bảo cốt để hoài niệm chứ không dám đào lại. Dò hỏi, nó xác nhận Bổ Thiên Các đã bị chư giáo liên thủ đại phá — sư huynh sư tỷ, trưởng lão và cả lão tổ đều chết trận để che chở môn đồ rời đi, khiến nó đau đớn. Biết tứ đại gia tộc cùng các thế lực địch đang giăng lưới ở Sơ Thủy Địa tìm cá lọt lưới, Nhóc Tỳ dùng bảo thuật của Mao Cầu đổi dung mạo thành dáng gậy trúc rồi tung tin đồn Hùng Hài Tử còn sống. Khi đám người mang sát khí ập tới truy hỏi, nó cảm ứng phù văn của tứ đại gia tộc, Vũ Tộc, Thác Bạt Tộc và đánh lạc hướng sang Điểu Gia cùng Tinh Bích đại gia. Hai lão bị vây liền đòi bán tin tức giá cao, cãi nhau tố nhau lừa đảo, và con chim trên vai Điểu Gia đập cánh đánh bay kẻ ra tay khiến cả đám không dám động, hé lộ họ là cao thủ ẩn mình. Nhóc Tỳ truyền âm bắt tay hai lão, dựng màn bán tin tức về chính mình để ép các thượng cổ đại giáo mang nguyên thủy bảo cốt hoặc bảo huyết thái cổ di chủng tới đổi, mở màn kế báo huyết thù; tin đồn lan tới cả các động thiên phúc địa cao hơn."},{"chuong":204,"tieuDe":"Thu Đại Lễ","tomTat":"Tin thằng nhỏ đầu gấu Nhóc Tỳ không chết ở Bổ Thiên Các dù chư giáo liên thủ vây ép lan nhanh từ Sơ Thủy Địa lên các động thiên phúc địa cao hơn, khiến Tứ đại gia tộc, Vũ Tộc, Thác Bạt thế gia và các thế gia cổ đều phái người tới tìm chứng cớ vì kiêng kỵ thiên phú của nó. Hai lão già bịp bợm Tinh Bích đại gia và Điểu Gia rao bán tin tung tích, đòi trao đổi bằng phù cốt hoặc bảo huyết. Khi một nhóm cường giả định dùng vũ lực bức họ nói thật và giăng bảo thuật phù văn bao vây, con chim của Điểu Gia bay lên tế xuất ánh lửa từ trời biến nơi này thành ao lửa, nướng gần chín cả nhóm khiến ai nấy đều bỏ ý định vũ lực. Phong vân tụ hội, Xích Vân công tử, đại công tử Thác Bạt Tộc và người Vũ Tộc lần lượt hàng lâm; hai lão ra giá đòi mỗi đại giáo góp một bình bảo huyết thái cổ di chủng, tổng ít nhất 15 bình mới nói tung tích. Các thế lực lần lượt đặt bình máu tím, lam quang, đỏ thẫm, vàng lên bàn đá. Nấp trong bóng tối, Nhóc Tỳ — đã đột phá cực cảnh gần như vô địch tại đây và nhận diện được khí tức Vũ Tộc — chờ số bình vượt 15 rồi vọt ra từ trên trời gom toàn bộ bàn bảo huyết vào lòng, hô đòi tiền lãi cho sư môn đã chết và hét lớn của ta của ta đều là của ta."},{"chuong":205,"tieuDe":"Đại Khai Sát Giới","tomTat":"Nhóc Tỳ nhanh tay bọc đống bình ngọc bảo huyết vào tấm da thú, rồi khi bị đối phương triển khai pháp trận sao vây khốn, nó mọc đôi cánh Côn Bằng đánh nổ các ngôi sao lớn và vọt mấy trăm trượng thoát ra. Đám đông nhận ra kẻ này chính là 'thằng nhỏ đầu gấu' sống sót sau trận huyết sát ở Bổ Thiên Các, tin tức truyền đi khắp nơi khiến người đổ về Sơ Thủy Địa của Hư Thần Giới tăng vọt. Khi Tinh Bích và Điểu Gia đứng ra đòi bảo huyết, Vũ Tộc cùng tứ đại gia tộc mắt đỏ xông tới, còn Tứ công tử Thác Bạt Tộc ôm Ly Hỏa Thần Tàm giăng lưới Ly Hỏa Tàm Ti hòng bắt sống nó. Nhóc Tỳ dùng Kim Tuyền Ba Văn Công tạo vòng xoáy vàng nuốt sạch Ly Hỏa, xé rách lưới tơ bằng tay không, rồi thi triển bảo thuật Thần Côn trói và giậm chân giết chết Tứ công tử tại chỗ. Không thể thuần phục con tằm thần, nó bóp chết Ly Hỏa Thần Tàm và cất huyết nhục làm bảo dược, khiến những kẻ tử vong nơi đây cũng bị trọng thương hao tổn nguyên khí ở thân thật. Cảm nhận khí tức quen thuộc, Nhóc Tỳ xách lên thiếu niên áo trắng Vũ Phong — thiên tài Vũ Tộc từng dẫn tộc nhân đến Bổ Thiên Các lấy oán trả ơn — giật đứt cánh tay hắn để hành hạ. Nhớ lại huyết sát kiếp năm xưa, nó phát cuồng dùng bảo thuật Côn Bằng kết hợp lôi điện tàn sát tộc nhân Vũ Tộc nổ tung thành mưa máu và truy sát nhân mã hơn mười tộc, đại khai sát giới."},{"chuong":206,"tieuDe":"Đánh Đâu Thắng Đó","tomTat":"Một liên minh tạm thời của nhiều đại giáo cùng ra tay nhưng bị Nhóc Tỳ giết liểng xiểng bằng cánh Côn Bằng và tia điện, khiến Vũ Tộc tổn thất hai ba mươi người chỉ trong nháy mắt. Vũ Tộc buộc phải bày sát trận Giao Long từ mười mấy khối nguyên thủy bảo cốt xương Giao, nhưng Nhóc Tỳ trong trạng thái Hùng Hài Tử cực cảnh chém đứt các con Giao Long rồi phóng con Toan Nghê tím to hơn núi nuốt Hôi Giao, làm phù cốt nứt vỡ. Nó giết sạch người Vũ Tộc, chỉ chừa Vũ Phong rồi xé đôi tên này; ở Cổ Quốc hiện thực, phủ đệ Vũ Tộc mấy chục người ho ra máu, có người rách mi tâm vì hư thân bị giết. Thác Bạt Tộc tung ra Diệt Hồn Châm — ma khí đỏ đậm giết được cả chân thân — nhưng Nhóc Tỳ né tránh rồi dùng đỉnh lôi điện tím hút lấy mười hai cây thần châm và dùng phù văn mi tâm khống chế, đoạt luôn khỏi tay địch. Nó tuyên bố chỉ dành châm cho cao tầng các giáo, chặn trước thông đạo màu vàng không cho ai thoát khỏi Hư Thần Giới. Điều khiển toàn lực bảo thuật Côn Bằng cùng sóng biển đen, Nhóc Tỳ áp chế mọi sát trận trấn giáo và diệt sạch cao thủ chư giáo không sót một ai trong Sơ Thủy Địa. Cuối cùng bia đá hiện chữ báo lập kỷ lục giết chóc, một luồng hào quang mông lung từ trời giáng xuống mang theo một vật thần bí rơi tới gần nó, còn người các đại giáo ở hiện thực thì tức đến ói máu, thương thế nặng thêm."},{"chuong":207,"tieuDe":"Sách Thần Thái Cổ","tomTat":"Sau khi Nhóc Tỳ một mình diệt sạch hơn mười nhóm thế lực cùng hàng trăm cao thủ tại Vùng đất ma quỷ, đám người xem chiến đều nhục nhã vì trở thành bàn đạp cho chiến tích của nó, tin tức lan khắp Hư Thần Giới lẫn các Cổ Quốc khiến Sơ Thủy Địa sôi trào. Pháp tắc trật tự thế giới cảm ứng kỷ lục vừa lập, ban xuống một chùm sáng nứt ra để lộ mảnh đồng thau dị thường cực cứng, với bia đá hiện bốn chữ Đấu Chiến Tiểu Thánh và chú thích rằng đây là một phần mười của sách thần thời Thái Cổ. Tinh Bích đại gia giả thế ngoại cao nhân đòi giúp đánh giá, Điểu Gia đề nghị đổi một môn bảo thuật tuyệt thế, nhưng Nhóc Tỳ cảnh giác ôm chặt mảnh vỡ, gọi Tinh Bích là lão già lừa đảo và đe dọa không cho ai lại gần. Có người tiết lộ gom đủ toàn bộ mảnh vỡ đồng thau sẽ mở ra một tòa tiên tàng chứa bảo thuật cái thế Thái Cổ, nhưng phải tiếp tục phá những kỷ lục gian nan bất khả. Nhóc Tỳ hớn hở tuyên bố giết xong Sơ Thủy Địa sẽ tiến vào các động thiên phúc địa khác để phá thêm kỷ lục, khiến Vũ Tộc, Thác Bạt Tộc và tứ đại gia tộc biến sắc và mưu tính chờ nó lên cảnh giới Động Thiên sẽ ra tay giết cả hư thân lẫn chân thân, mở màn cho một trận giông bão đang dâng lên."},{"chuong":208,"tieuDe":"Không Còn Lo Âu","tomTat":"Các lão tổ gia tộc Thượng Cổ chấn động khi một mảnh sách quý đồng thau xuất hiện, bàn tán rằng Nhóc Tỳ bộc phát quá sớm có thể suy tàn khi lên Động Thiên Cảnh, còn Vũ Tộc và Thác Bạt Tộc thì mong ngóng một trận đại chiến với nó. Tại Sơ Thủy Địa, Nhóc Tỳ gài bẫy Tinh Bích đại gia và Điểu gia bằng cách công khai lấy ra bảo huyết di chủng Thái Cổ trước đám đông đại giáo, khiến hai lão bị nghi lừa gạt chư giáo mà không dám nhận. Khi hai lão nổi giận ra tay, Nhóc Tỳ phản kích bằng thập tinh quán nhật và sấm chớp tinh khiết làm Điểu gia cháy đen, còn nhổ trụi nửa bộ lông thần tước năm màu, trong khi Tinh Bích đại gia không dám can thiệp. Cuối cùng nó giao bảo huyết, cho hai lão xem một góc vỡ sách đồng thau và bí mật thương lượng, mời cả hai làm hộ pháp bảo vệ thôn — thu hoạch lớn nhất khiến nó hoàn toàn yên tâm. Trở về thôn dưới Liễu Thần, Nhóc Tỳ hứa dẫn cả thôn vào Hư Thần Giới, tặng hơn mười bình bảo huyết để mọi người gột rửa thân thể. Sáng hôm sau, cả thôn hành lễ Liễu Thần rồi cùng qua thông đạo màu vàng đến Sơ Thủy Địa, đám thiếu niên gây náo loạn như cả một bầy Hùng Hài Tử. Nhóc Tỳ giao đám thiếu niên ngang bướng cho hai lão hộ pháp, rồi mở thông đạo màu vàng tuyên bố đi động thiên phúc địa cao cấp hơn để đánh hạ một giang sơn to lớn và biến mất, khiến Sơ Thủy Địa sôi trào."},{"chuong":209,"tieuDe":"Động Thiên Phúc Địa","tomTat":"Nhóc Tỳ theo thông đạo màu vàng tiến vào động thiên phúc địa cao cấp của Hư Thần Giới, khiến Sơ Thủy Địa sôi trào và cả Hư Thần Giới lẫn Cổ Quốc chấn động vì xác nhận nó hành động thật. Tại hoàng cung Hỏa Quốc, Hỏa Linh Nhi tức giận vì bị gọi là mập, trách sói con nghe lời tên kia và quyết đi Hư Thần Giới xem nó ăn quả đắng; đồng thời một thiếu nữ áo tím tỉnh dậy từ động phủ trên thần sơn, tỏ ý ghét Hùng Hài Tử. Các tộc như Vũ Tộc, Thác Bạt Tộc mưu tính đuổi sói nuốt hổ bằng cách lôi kéo sinh linh Thái Cổ thuần huyết, nhưng ngại Thần Sơn Thái Cổ là cấm địa không ai dám đụng. Nhóc Tỳ khám phá thế giới thần giới linh khí dày đặc, ăn thử linh dược thấy tinh khí tăng, rồi tới Động Thiên Thành nện chân làm nứt nham thạch và bị bia đá Hư Thần Giới cảnh cáo trục xuất. Nó tuyên bố mỗi gia tộc phải nộp mười bình bảo huyết di chủng trong một canh giờ, chọn Vũ Tộc làm mục tiêu báo thù đầu tiên vì từng hãm hại Bổ Thiên Các. Hết hạn, Hùng Hài Tử tuyên chiến thảo phạt diệt sạch Vũ Tộc và xóa tên khu động thiên phúc địa, trong khi Vũ Tộc bày đại sát trận và nhắc tới Nghị nhi đã rời Thánh Viện Thượng Cổ như át chủ bài. Nhóc Tỳ chuẩn bị mười hai cây Diệt Hồn Châm rồi rút thanh kiếm gãy màu đen bổ mạnh vào tịnh thổ Vũ Tộc, kiếm khí như dãi ngân hà chém thẳng xuống, mở màn trận đấu."},{"chuong":210,"tieuDe":"Một Mình Chiến Vũ Tộc","tomTat":"Nhóc Tỳ một mình xông vào tịnh thổ Vũ Tộc trong Hư Thần Giới, vung kiếm gãy tạo kiếm khí như đại dương chém đôi quần thể kiến trúc, phá vỡ sát trận Vũ Tộc bày sẵn. Nó dùng bảo thuật Côn Bằng phóng linh vũ vàng giết gần trăm người Vũ Tộc, buộc tộc dùng Thủy Mặc Già Thiên chắn đòn; đòn giết này khiến chân thân Vũ Tộc bên ngoài trong Vũ Điểm phủ ở Cổ Quốc bị trọng thương liên lụy. Khi Vũ Tộc tế ra Ngân Thiên Lang từ tấm da dị chủng Thái Cổ, Nhóc Tỳ dùng bảo phiến máu cướp của Uyên Tộc thiêu nó thành Hỏa Lang rồi đánh gãy xương sống, buộc tộc thu hồi bảo cụ chỉ còn tấm da sói cháy thủng lỗ. Nhóc Tỳ đứng trước tịnh thổ mắng Vũ Tộc hèn nhát co đầu rút cổ, làm mất mặt cả đại tộc Vương Hầu trước quần hùng đang quan sát. Vũ Tộc phản kích bằng sát trận vô lượng và một tòa pháo đài bảo cốt, nhưng Nhóc Tỳ dùng kiếm gãy đánh nổ tung chí bảo trấn tộc này, khiến các lão Vũ Tộc phun máu; đồng thời Vũ Tộc kinh hoàng nhận ra kiếm gãy rất giống thanh kiếm của Thủy Tổ Bổ Thiên Các. Nhóc Tỳ tiếp tục dùng chín tòa Động Thiên đoạt tạo hóa tấn công tịnh thổ, trong khi một lão tổ Vũ Tộc quyết chỉ được thắng không được bại, nhắc tới việc chờ Nghị nhi xuất quan và quyết đi nghênh Pháp Chỉ Thần Linh để diệt cả hư thân lẫn chân thân của Nhóc Tỳ."},{"chuong":211,"tieuDe":"Pháp Chỉ Của Thần Linh","tomTat":"Ở nơi sâu nhất Vũ Tộc ngoài thế giới hiện thực có một miếu thần phát sáng như đúc bằng vàng thờ Vũ Thần — vị thần tổ truyền ngôn đã chết trong trận chiến Thượng Cổ. Lão tổ Vũ Tộc dẫn đám người cúng bái rồi mở chiếc bình đen chứa mười tờ giấy vàng đất nát bét ghép thành pháp chỉ cuối cùng của Vũ Thần, cho mọi người nhỏ máu chứng minh hậu duệ. Thiếu nữ thông linh Vũ Tử Mạch nhắm mắt chọn tờ pháp chỉ ghi chữ “Phạt”, đủ mạnh chém mọi địch thủ trong Hư Thần Giới. Trong Hư Thần Giới, đại trận Vũ Tộc triệu các di chủng Thái Cổ cản Nhóc Tỳ, kiếm gãy không công phá nổi phù văn còn điên cuồng nuốt tinh khí thần của nó. Nhóc Tỳ lộ Động Thiên trước quần hùng, tăng từ năm tòa lên bảy rồi mở tới chín tòa dung nham khiến quần hùng chấn kinh vì điều này chỉ ghi trong sách cổ với Nhân Tộc. Vũ Tộc thu trận rồi bộc phát pháp chỉ Thần Linh chữ “Phạt”, ảnh hưởng cả quy tắc trật tự Hư Thần Giới và trút mưa ánh sáng vàng đánh Nhóc Tỳ đầy lỗ máu. Dù bị thương, Nhóc Tỳ không lùi mà chửi mắng, liều mạng tiến lên quyết chém nát pháp chỉ, lý luận rằng Vũ Thần đã chết nên tờ giấy nát không thể nghịch thiên; phương xa thiếu nữ áo tím từ Thần Sơn Thái Cổ và thiếu nữ áo đỏ ôm sói con đờ người chứng kiến."},{"chuong":212,"tieuDe":"Xúc Phạm Thần Linh","tomTat":"Nhóc Tỳ buông lời mắng chửi thách thức Thần Linh của Vũ Tộc, dùng kiếm gãy tuôn hàng trăm ngàn vệt kiếm khí bổ vào pháp chỉ chữ ‘Phạt’ và đánh bay tờ bùa xa mấy trăm trượng, khiến cả Vũ Tộc kinh hãi vì một đứa bé lại chống được pháp chỉ Vũ Thần. Đám già Vũ Tộc trong vùng tịnh thổ ngồi xếp bằng ngâm thần chú Tế Vũ Thần khiến pháp chỉ thức tỉnh mạnh hơn, hóa thành vầng mặt trời vàng óng phun mưa mặt trời màu vàng và lôi điện. Nhóc Tỳ thi triển bảo thuật Côn Bằng hợp nhất kiếm gãy há miệng nuốt pháp chỉ khiến tờ giấy tạm biến mất, nhưng nó hồi phục với một vết rách rồi tiếp tục phóng chữ ‘Phạt’ như bảo cụ và tia chớp như dải ngân hà. Nhóc Tỳ triển Toan Nghê màu tím cao bằng núi lớn cắn nuốt tia chớp và xé chữ ‘Phạt’, dù bị đánh thủng hơn hai mươi lỗ máu thân thể gần nát vẫn kiên trì không lùi. Trước đòn cuối là ngôi sao lớn của pháp chỉ, kiếm gãy rốt cuộc thức tỉnh cắt tờ giấy thành hai nửa, tiểu tháp trên sợi tóc va chạm ngăn được chữ ‘Phạt’. Cuối cùng nơi ngực Nhóc Tỳ bùng phát khí tức đáng sợ như hố đen nuốt chửng chữ ‘Phạt’, tinh huyết Chí Tôn không ngừng tăng cường, thai nghén ra sinh cơ vô tận."},{"chuong":213,"tieuDe":"Tư Chất Ngút Trời","tomTat":"Ngực Nhóc Tỳ nóng rực, lồng ngực trong suốt hé lộ Chí Tôn Cốt — khối xương chưa thành hình được máu tươi thai nghén — đang rút tinh hoa thần tính chữ “Phạt” của pháp chỉ Thần Linh để tẩm bổ, nhưng tinh hoa không trọn vẹn nên chưa đủ lột xác. Pháp chỉ vỡ nát, Nhóc Tỳ sống sót khiến Vũ Tộc và quần hùng kinh ngạc, rồi nó nhai nuốt cả hai nửa tờ giấy khiến các lão giả Vũ Tộc hộc máu; Hỏa Linh Nhi ví nó là Thao Thiết chuyển thế. Bia kỷ lục Hư Thần Giới hiện ra ghi nó chiến bại ý chí Thần Linh, ban thưởng hai miếng đồng thau Thái Cổ Thần Thư nâng tổng lên ba miếng. Nhóc Tỳ uống bảo huyết di chủng hồi phục rồi xông vào tịnh thổ, phá mười một tầng đại trận, thi triển kiếm gãy (chín Động Thiên), bảo thuật Toan Nghê và Côn Bằng giết hàng chục người, dùng Diệt Hồn Châm giết một nguyên lão Vũ Tộc thân phận cực cao. Một ông lão nham hiểm kích nổ cấm trận trung tâm, giết hơn trăm cao thủ Vũ Tộc lẫn khiến Nhóc Tỳ trọng thương gần đứt rời thân thể, còn bọn Vũ Tộc định dùng Trấn Hồn Tháp luyện hóa nó thành thân tử đạo tiêu. Trong nguy nan, Nhóc Tỳ tự đốt tinh khí thần chữa thương, bộc phát tinh khí sinh mệnh và tự mình mở tòa Động Thiên thứ mười, khiến quần hùng kinh ngạc gọi là thần thoại."},{"chuong":214,"tieuDe":"Vô Đề","tomTat":"Trong lúc giao chiến với Vũ Tộc tại Hư Thần giới, Nhóc Tỳ bất ngờ làm hiện dấu hiệu Động Thiên thứ mười, cảnh giới thần thoại vượt trên chín Động Thiên. Vũ Tộc kinh hoàng phản kích bằng vạn phù tiễn, bảo ấn hóa núi, đại trận tịnh thổ và thần chu chặn đường, nhưng lần lượt bị Toan Nghê tím, Côn Bằng và kiếm gãy của Nhóc Tỳ phá tan. Nhóc Tỳ nhận ra tòa Động Thiên thứ mười cần bản thân chủ động đoạt tạo hóa để thành hình, song chiến trường hỗn loạn khiến việc vượt ải liên tục bị quấy nhiễu. Cậu dùng đỉnh lôi điện luyện hóa và đoạt Trấn Hồn Tháp, rồi dùng Diệt Hồn Châm giết Lục thúc tổ và Tứ thúc tổ, khiến Vũ Tộc chịu tổn thất nặng. Sau đó Nhóc Tỳ đại khai sát giới bằng Toan Nghê tím và đại dương màu đen, giết hàng trăm người Vũ Tộc, ngăn họ mở đại trận cuối cùng. Khi định rút đi để chuyên tâm mở Động Thiên thứ mười, cậu bị Ly Long thuần huyết chặn đường đòi Thanh Đồng Bảo Thư, rồi lại gặp một thiếu niên Nhân Tộc lạ đã mở chín Động Thiên và mang chí bảo. Chương kết ở thế Nhóc Tỳ vừa chiến đấu với hai đối thủ mạnh vừa tiếp tục cố mở Động Thiên thứ mười, thậm chí đe dọa sẽ ăn hết cả hai nếu bị chọc giận."},{"chuong":215,"tieuDe":"Đại Địch","tomTat":"Nhóc Tỳ đang mang trọng thương sau trận đối kháng pháp chỉ Thần Linh thì bị hai đại địch vây công tại tịnh thổ Vũ Tộc: một thiếu niên Nhân Tộc thần bí có thân thể như Man Thần và một Ly Long thuộc dòng hung thú Thái Cổ. Thiếu niên Nhân Tộc ép giao Thái Cổ Thần Thư, còn Ly Long nhắm tới bảo thư đồng thau, khiến cuộc chiến xoay quanh cả sinh tử lẫn đoạt bảo. Nhóc Tỳ vận dụng cốt văn từ Nguyên Thủy Chân Giải, triệu lôi hải, Toan Nghê và Côn Bằng để đối kháng với Bệ Ngạn, Bạch Hổ cùng hoa văn hình rồng của Ly Long. Trong cận chiến, Nhóc Tỳ và thiếu niên Nhân Tộc đều bị thương nặng, máu văng khắp nơi, còn tịnh thổ Vũ Tộc càng bị tàn phá. Nhóc Tỳ nhiều lần muốn mở Động Thiên thứ mười để lột xác nhưng bị Ly Long liên tục cản phá. Khi bị Ly Long quấn chặt định nuốt, nó cắn ngược, phá nát hơn mười vảy và nuốt máu thịt đối phương, làm quần hùng kinh ngạc. Cuối chương, Nhóc Tỳ nảy ý định mượn sức hai đại địch để ép mở Động Thiên thứ mười, sau đó quét ngang các đối thủ trong khu vực."},{"chuong":216,"tieuDe":"Hi Vọng","tomTat":"Quần hùng chấn động trước Nhóc Tỳ, một thiếu niên loài người mới mười bốn mười lăm tuổi đã mở chín Động Thiên và đủ sức giao chiến với các thiên tài tuyệt đỉnh. Trong trận huyết chiến, nó bị thiếu niên dã tính thân màu đồng cổ và Ly Long vây công, cả hai đều là cường giả chín Động Thiên, khiến nó rơi vào tình thế nguy hiểm nhất từ trước đến nay. Sau khi nhận ra Động Thiên thứ mười không thể dựa vào thiên tài địa bảo mà phải tự chớp lấy tạo hóa, Nhóc Tỳ mạo hiểm dùng Kim Tuyền Ba Văn Công hút thần lực của hai đối thủ để cưỡng ép phá quan. Sóng chấn từ quá trình mở ải khiến các thế lực như Thác Bạt Tộc, Tây Lăng Thú Sơn và tứ đại gia tộc không thể lại gần, nhưng sau hơn một canh giờ, lần trùng kích ấy vẫn thất bại sát nút, làm cả ba trọng thương, riêng Nhóc Tỳ suýt thân tử đạo tiêu. Tin tức nó nhổ tận gốc tịnh thổ Vũ Tộc, giết tám phần mười cường giả và ăn cả pháp chỉ Thần Linh lan khắp Hoang Vực, khiến nhiều đại giáo liên thủ phong tỏa Hư Thần Giới, chuẩn bị ma khí để truy sát. Hỏa Linh Nhi lo lắng cho rằng nó quá liều lĩnh, bởi ngay cả sinh linh thuần huyết Thái Cổ muốn phá quan nghịch thiên cũng cần cường giả cổ lão hộ đạo. Bị truy sát suốt nửa tháng, thân thể rách nát đến mức gần như dầu cạn đèn tắt, Nhóc Tỳ bước vào tử địa, buông lỏng sinh tử và bất ngờ ngộ ra con đường niết bàn của riêng mình. Trong khoảnh khắc cận tử hồi sinh, tiềm năng ẩn giấu bùng phát, thương thế khép lại, Động Thiên thứ mười được nối liền và bắt đầu hiện ra như một vùng tiên cảnh."},{"chuong":217,"tieuDe":"Mười Động Thiên","tomTat":"Trong rừng rậm Hư Thần Giới, Nhóc Tỳ trọng thương gần chết nhưng vẫn kiên trì mở Động Thiên thứ mười. Sau nửa tháng chịu dày vò như địa ngục, nó rốt cuộc thành công, được khí lành của Động Thiên tẩm bổ, trải qua niết bàn tái sinh và khôi phục hoàn toàn. Mười Động Thiên giao hòa như mười mặt trời, đưa nó lên đỉnh cao cảnh giới Động Thiên, được gọi là Cực Cảnh. Khi tỉnh lại, Nhóc Tỳ cảm ngộ Hư Thần Giới không khác thế giới thực, những gì xảy ra ở đây cũng có thể liên hệ tới bên ngoài. Trong khi đó, Tây Lăng Thú Sơn, Thác Bạt Tộc và Vũ Tộc tung tin rằng nó đã lỡ mất cơ hội mở mười Động Thiên, khiến nhiều thế lực tin nó thất bại. Các công tử Thác Bạt dẫn hơn trăm người tới trước, Nhị công tử và Lục công tử còn cá cược ai giết Nhóc Tỳ trước, trong lúc Vũ Tộc, Ly Long, các đại giáo cổ và nhóm vì Thanh Đồng Bảo Thư cũng đang đuổi tới."},{"chuong":218,"tieuDe":"Thiếu Niên Chí Tôn","tomTat":"Các thế lực trong dãy núi cùng kéo tới săn Nhóc Tỳ vì tin rằng trên người nó có Thanh Đồng Thần Thư, bảo vật vô giá khiến Vũ Tộc, cổ thế gia Thác Bạt, Tây Lăng Thú Sơn và nhiều giáo phái cùng tranh đoạt. Họ phát hiện dấu vết máu khô trong rừng và tưởng Nhóc Tỳ đã trọng thương đến mức đèn cạn dầu, trong khi Nhóc Tỳ lại đang uất ức vì mở thành công Động Thiên thứ mười mà Hư Thần Giới không ban thưởng hay dựng bia kỷ lục. Hai công tử Thác Bạt và các lão thành hai tộc tranh nhau quyền giết Nhóc Tỳ, còn Nhị công tử cầm Diệt Hồn Châm định diệt cả hình thần đối thủ. Khi một cường giả Vũ Tộc chỉ mặt khiêu khích, Nhóc Tỳ chỉ một ngón tay đã khiến hắn nổ tung, rồi tiếp tục bộc phát thần uy Chí Tôn của mười Động Thiên. Phù văn vàng quanh người nó hóa thành vùng thần vực, phân giải bảo thuật và nghiền nát những kẻ xông tới; Lục công tử bị kéo tới và bị châm thần đỏ đâm chết, Nhị công tử cũng bị đoạt châm, đánh nát bảo cụ rồi chết dưới chính pháp bảo của mình. Cuối cùng Nhóc Tỳ dùng phù văn vàng giam giữ hư không, khiến toàn bộ đám vây săn bất động rồi nổ tung thành tro tàn, sau đó rời khỏi khu rừng trong hào quang sáng rực."},{"chuong":219,"tieuDe":"Quét Ngang","tomTat":"Vô số thế lực kéo vào khu rừng nguyên thủy để truy tìm Nhóc Tỳ, vì Thanh Đồng Bảo Thư hắn mang theo được xem là Thái Cổ Thần Thư có giá trị khó đo lường. Một nhóm liên minh tán tu tìm thấy hắn trước, tưởng hắn đã sức cùng lực kiệt nên uy hiếp đòi giao bảo thư, nhưng bị Nhóc Tỳ dùng nhãn quang xuyên phá bốn đầu lĩnh rồi triệu Toan Nghê lôi đình nuốt sạch mấy chục người. Sau đó quần hùng vây tới đông hơn, trong đó Tây Lăng Thú Sơn đưa sáu đại di chủng như Bích Lân Báo, Kim Tình Long Giác Sư và Ác Ma Viên tới đòi độc chiếm bảo thư, còn các đại giáo Nhân Tộc và gia tộc Thượng Cổ tranh chấp quyền sở hữu. Tứ đại gia tộc Côn, Ly, Mông, Uyên cũng xuất hiện với thù hận sâu, mang ma khí và vật quan trọng nhất trong tộc nhằm giết cả hư thân lẫn chân thân của Hùng Hài Tử trước khi bàn chuyện bảo thư. Nhóc Tỳ trực diện nghênh chiến, một quyền bùng sáng như thái dương đánh nổ Bích Lân Báo to như núi. Hắn tiếp tục thi triển bảo thuật Côn Bằng bằng sức mạnh mười Động Thiên, hóa lông thần thành vô số thiên kiếm vàng, giết vô số nhân mã tứ đại tộc và cướp sạch ma khí của các đầu lĩnh. Cuối chương, Nhóc Tỳ như Ma Thần đạp thi thể địch nhân tiến ra khỏi dãy núi, một mình truy sát quần hùng và quét ngang tất cả."},{"chuong":220,"tieuDe":"Chấn Động Hoang Vực","tomTat":"Nhóc Tỳ sau khi tưởng đã gần chết bất ngờ hồi phục, sức chiến đấu tăng vọt và một mình truy sát quần hùng trong dãy núi. Viện quân các giáo tới để đoạt Thanh Đồng Cổ Thư nhưng bị cảnh tượng trước mắt làm kinh hãi, rồi tiếp tục bị phù văn màu vàng của cậu nghiền ép. Nhóc Tỳ xông vào Động Thiên Thành, giết thẳng tới tịnh thổ Thác Bạt Tộc, khiến Nhị công tử và Lục công tử chết trận, còn lão tổ phải dùng Tổ Khí đưa người còn lại chạy thoát. Chương xác nhận cậu đã mở mười Động Thiên, nắm thần uy Chí Tôn, sau đó phá tiếp tịnh thổ Côn Tộc, Ly Tộc, Uyên Tộc và cướp sạch nhiều cổ giáo, làm cả Hư Thần Giới lẫn Hoang Vực chấn động. Ly Long tự tìm tới quyết chiến nhưng bị Nhóc Tỳ đánh bại, bắt lại và hầm thịt ăn. Hỏa Linh Nhi dẫn đại quân theo lệnh Hỏa Hoàng tới cứu cậu nhưng nổi giận vì bị gọi là bé mập mạp. Cuối chương, Thiếu nữ áo tím bí ẩn xuất hiện cùng một ông già bị sương mù bao phủ, và Nhóc Tỳ gọi nàng là Hung thú, đòi đưa về thôn."},{"chuong":221,"tieuDe":"Tôn Giả Thần Sơn","tomTat":"Thiếu nữ áo tím đối đầu Nhóc Tỳ nhưng bị hắn gọi là hung thú, khiến nàng tức giận vì nhớ lại nỗi nhục từng bị vật lộn ở Bách Đoạn Sơn. Nhóc Tỳ chủ động tấn công, một hơi tinh khí hóa kim quang mang phù văn đã phá được cốt văn bảo thuật của nàng, làm nàng nhận ra hắn đã mở Động Thiên thứ mười. Nàng dùng sừng thần và bông tai chí bảo để ngăn cận chiến, song vẫn bị Nhóc Tỳ đánh xuyên qua lớp phòng ngự. Tổ phụ của nàng ra tay, bộc lộ khí tức siêu phàm và sức mạnh chín Động Thiên, đồng thời muốn nói với Nhóc Tỳ về một hồi đại nhân quả, đại cơ duyên. Nhóc Tỳ không nghe, liên tiếp thi triển bảo thuật Côn Bằng và Toan Nghê, đánh lão già chật vật, thâm tím hai mắt, bốc khói và chỉ chăm chăm đòi đoạt bao tay thần binh. Lão tiết lộ bao tay là binh khí của Thần minh nhưng vẫn không dọa được Nhóc Tỳ; cuối cùng lão định bỏ đi rồi bị vật ngã, còn thiếu nữ áo tím xin thay tổ phụ ra tay và lại bị Nhóc Tỳ chộp tay định vật lộn."},{"chuong":222,"tieuDe":"Thập Hung Di Thuật","tomTat":"Nhóc Tỳ giao chiến với thiếu nữ áo tím và lão già đến từ Thái Cổ Thần Sơn, dùng phù văn cùng bảo thuật áp đảo đối thủ; thiếu nữ nhờ khuyên tai phát quang mới thoát khỏi thế bị trấn áp. Trong mảnh thiên địa này, Nhóc Tỳ mở cả mười Động Thiên, thần uy khiến quần hùng chấn động và nghi ngờ lai lịch của nó không đơn giản. Lão già ban đầu muốn trấn áp Nhóc Tỳ nhưng sau khi thấy mười Động Thiên thì đổi ý, tiết lộ tin tức tổ Thái Cổ Côn Bằng ở hoang vực giáp biển, nơi có thể ẩn giấu bảo thuật Thập Hung thất truyền. Nhóc Tỳ nghi ngờ đối phương dụ mình mở đường rồi hạ sát nên không dễ tin, dù lão già đề nghị dùng thượng cổ trớ chú phát thệ. Cuối cùng Nhóc Tỳ đặt điều kiện nhờ lão tìm phụ mẫu năm xưa đi Thái Cổ Thần Sơn hái thánh dược rồi mất tích. Sau đó nó cảm ơn Hỏa Linh Nhi, trở về Sơ Thủy Địa và mở thông đạo tới Hỗn Độn Phế Khư Địa để cầu viện Liễu Thần, vì chỉ tin Liễu Thần có thể chi viện khi bước vào cấm địa."},{"chuong":223,"tieuDe":"Thành Giao","tomTat":"Liễu Thần nghe Nhóc Tỳ kể lại mọi chuyện, phán đoán bảo thuật Côn Bằng nếu còn tồn tại thì sẽ nằm ở hải vực, nên khuyên nó đi tranh đoạt một lần dù chuyến đi rất nguy hiểm. Liễu Thần cũng chỉ ra rằng Nhóc Tỳ ở chốn thiên địa kia có thể trấn giết lão già, đồng thời khen việc tự mở mười Động Thiên là cực kỳ hiếm thấy và dặn sau khi trở về sẽ tẩy lễ cho nó. Nhóc Tỳ quay lại gặp lão già, liên tục mặc cả: muốn giải phù văn trong cơ thể Ly Long, đòi bảo thuật, rồi mượn được một chiếc bao tay bảo cụ để dùng trong chuyến ra hải ngoại. Nó còn âm thầm hiển hóa hình dáng một đôi nam nữ, yêu cầu lão già dò tin tức của họ và không được để lộ phong thanh, khiến lão phải thỏa hiệp. Khi lão già định rời đi, Nhóc Tỳ giữ Ly Long lại để đòi chuộc, cuối cùng hai Hoàng Kim Thú phải dùng một bộ cổ pháp thiên lôi không hoàn chỉnh đổi lấy thiếu chủ. Nửa tháng sau trở về Thạch Thôn, Nhóc Tỳ thấy Liễu Thần đang chuẩn bị trọng đại; Liễu Thần nói trời đất sắp loạn, lần này vừa tẩy lễ cho Nhóc Tỳ vừa tự lột xác, tiến thêm một bước và chữa trị thương thế, khiến Nhóc Tỳ càng nôn nóng muốn mạnh lên."},{"chuong":224,"tieuDe":"Cực Cảnh Tẩy Lễ","tomTat":"Thạch Hạo tiếp tục tự tôi luyện trong đại hoang, cứng chọi cứng với cự thú, hàng phục Thổ Hành Long thứ tám rồi kéo đi xa để không uy hiếp Thạch thôn. Hắn còn đối kháng thác nước, dùng phù văn khiến thác đảo chiều chảy ngược, qua đó ép thân thể, phù văn và tinh thần tới cực hạn. Sau hai đến ba tháng, Liễu Thần phát thần âm gọi hắn trở về để tẩy lễ; cả Thạch thôn kinh động khi hơn mười cành liễu rủ xuống như dây xích thần. Bốn bình ngọc vỡ, bảo huyết tứ đại hung thú bùng phát thần uy hủy diệt nhưng được Liễu Thần thuần hóa thành cam lộ trút lên người Thạch Hạo. Vì đã đạt cực cảnh Động Thiên, thân thể hắn mạnh thêm nhưng phù văn không biến hóa lớn, khiến hắn chủ động tìm cách phá giới hạn bằng mười Động Thiên. Tinh khí thần hóa thành Chân Long chia vào mười Động Thiên, rồi Liễu Thần tiếp tục buông thần tính tinh hoa của chính mình, tạo sinh mệnh khí cơ khiến cây cỏ hồi sinh và thôn dân được lợi. Cuối cùng Thạch Hạo cô đọng tinh thần nhập vào mười Động Thiên, dung hợp chúng thành một tiên vực và nhận ra hướng tiếp theo để tiếp tục đột phá."},{"chuong":225,"tieuDe":"Tái Diễn","tomTat":"Nhóc Tỳ đạt trạng thái tinh thần dung hợp với mười Động Thiên, như nhìn thấy quá trình khai thiên và cách sinh mệnh diễn biến, từ đó thu nhận nhiều ấn ký đại đạo. Nó thử dồn tinh khí thần của chín Động Thiên cùng chất lỏng của Liễu thần vào một Động Thiên để tái diễn sinh cơ, nhưng các điểm sáng và cỏ cây vừa thành lại nổ tung. Sau ba tháng bế tắc, nó nghi ngờ mười Động Thiên chưa hẳn là cực hạn và quyết định mạo hiểm tự hủy một Động Thiên để tìm đường vượt cấm kỵ. Liễu thần không ngăn cản, chỉ nói đây là con đường của nó, còn mọi người trong thôn đều hoảng sợ can ngăn. Nhóc Tỳ tập hợp sức mạnh chín Động Thiên oanh kích Động Thiên còn lại, khiến bản thân phun máu, trọng thương, nhưng nhờ thân thể gần như bất hủ và Liễu thần trấn giữ nên vẫn sống sót. Nó nhiều lần chữa thương rồi tái tạo, song Động Thiên liên tục nổ tung, thân thể rách nát đến lộ xương trắng. Trong lúc thất bại, nó nhìn thấy mảnh vỡ áo nghĩa đại đạo và ngộ ra pháp tắc trường tồn, cuối cùng tái tạo được một Động Thiên lớn ngang Động Thiên thứ mười. Sau một ngày một đêm, mười Động Thiên đều được xây dựng lại hoàn tất, dao động thần năng kinh người, và Nhóc Tỳ cảm thấy dường như có biến hóa mới."},{"chuong":226,"tieuDe":"Lại Biến Hóa","tomTat":"Dưới gốc cây liễu, Nhóc Tỳ mở ra mười Động Thiên viên mãn, mỗi Động Thiên rộng lớn như một mảnh Tiên Giới, khiến Liễu Thần, Nhị Ngốc Tử, Đại Hồng Điểu và người Thạch thôn đều chấn động. Hắn thử tiến thêm một bước bằng cách dung hợp mười Động Thiên thành một phương thiên địa, nhưng các Động Thiên va chạm phá hủy lẫn nhau, làm thân thể hắn chịu phản chấn và tràn máu. Trong lần suy diễn tiếp theo, Nhóc Tỳ nhận ra thân thể mình có thể bị Động Thiên phân giải, còn Liễu Thần chỉ ra đó là con đường tế sống chính mình, một thủ đoạn cấm kị thương tổn thiên hòa và dễ dẫn tới thiên khiển. Nhóc Tỳ từ đó hiểu được có thể lật ngược thủ đoạn này khi địch nhân dùng Động Thiên công kích, nhưng hắn cũng cảm thấy mình đã đến cực hạn Động Thiên cảnh theo lối cũ. Sau hai canh giờ bế tắc, hắn quyết định đánh cược lần cuối, dùng thần dịch còn dư, thiêu đốt sinh mệnh và vận chuyển Phù Văn tập trung nơi ngực. Mười Động Thiên dần sinh liên hệ, xoay quanh thân hắn và cuối cùng hóa thành một vòng thần hoàn to lớn, thần hà chiếu cửu thiên, để Nhóc Tỳ đứng ở trung tâm với khí thế bễ nghễ thế gian."},{"chuong":227,"tieuDe":"Thành Công Cực Điểm","tomTat":"Thạch Hạo hoàn thành con đường tự khai mở ở Động Thiên cảnh khi thập đại Động Thiên tương liên giao hòa, hóa thành một vòng thần hoàn bao phủ thân thể, khiến Liễu Thần, Nhị Ngốc Tử, Đại Hồng Điểu và người Thạch Thôn chấn động. Thần hoàn từng giải thể làm mọi người lo hắn thất bại, nhưng sau đó lại tái hợp, truyền thần lực tinh hoa vào thân thể và khiến Chí Tôn Cốt hấp thu một phần lực lượng rồi ngủ say. Đại Hồng Điểu nhận ra thần hoàn đang dưỡng thành trạng thái thân thể Động Thiên, nơi quang đoàn trong cơ thể Thạch Hạo có thể tẩm bổ ra bảo thuật độc nhất của bản thân. Liễu Thần kết thúc tẩy lễ, còn Thạch Hạo thừa nhận quá trình từng nguy hiểm đến gần hình thần câu diệt nhưng cuối cùng vượt qua. Sau đó dân Thạch Thôn ùa tới vui đùa, người lớn trêu hắn chuyện lấy vợ, gả Hổ Nữu và sinh hậu nhân khiến hắn xám xịt bỏ chạy. Liễu Thần cho biết hắn có thể vào Hư Thần Giới nhận ban thưởng vì quy tắc nơi đó đã biến hóa, rồi mở thông đạo bằng cành liễu; ba tháng sau Thạch Hạo tái xuất ở Hư Thần Giới, khiến các thế lực chú ý và Thái Cổ Thần Sơn chờ hắn tiến vào Hóa Linh cảnh để tìm Di Thuật Thập Hung ngoài hải ngoại."},{"chuong":228,"tieuDe":"Sơ Văn","tomTat":"Nhóc Tỳ trở lại Sơ Thủy Địa, lập tức khiến các đại giáo phái và những người từng chịu thiệt dưới tay nó hoảng sợ. Nó rời Sơ Thủy Địa qua thông đạo màu vàng, đến khu vực từng khai mở Động Thiên thứ mười và nhận thêm hai mảnh Thanh Đồng Thư do Hư Thần Giới ban thưởng, nâng tổng số lên năm khối. Một bia đá hiện ra khắc bốn chữ Động Thiên Chí Tôn, xác nhận nó là người mạnh nhất Động Thiên cảnh trong Hư Thần Giới ở Hoang Vực. Sau đó các đại biểu Thái Cổ Thần Sơn tìm tới, trong đó thiếu nữ áo tím báo rằng chín năm trước cha mẹ nó từng quanh quẩn gần Thái Cổ Thần Sơn rồi đã thoát khỏi Hoang Vực. Tin này khiến Nhóc Tỳ chấn động, mắt đỏ và trầm mặc hồi lâu, còn thiếu nữ áo tím cảnh báo đại chiến hải vực sắp bùng nổ nên nó cần sớm tiến vào Hóa Linh cảnh. Rời khỏi đó, Nhóc Tỳ đi qua những Tịnh Thổ cũ của Vũ Tộc và Thác Bạt Tộc, rồi tới Võ Vương Phủ vì cảm nhận cha mẹ từng đặt chân nơi này. Khi bị người canh gác nhận ra và ngăn lại, nó chỉ nói mình tới đây làm khách."},{"chuong":229,"tieuDe":"Võ Vương Phủ","tomTat":"Nhóc Tỳ xuất hiện trước sơn môn Võ Vương Phủ trong Hư Thần Giới, khiến người canh giữ căng thẳng vì danh tiếng sát tinh của hắn sau các trận quét ngang đại giáo, Vũ Tộc và Thác Bạt Tộc. Một trưởng lão trong phủ ra nghênh đón, dẫn hắn vào Tịnh Thổ, nơi có linh dược, linh sơn và cung điện tu luyện. Nhóc Tỳ dò hỏi quan hệ thông gia giữa Võ Vương Phủ và Vũ Tộc, rồi chuyển sang truy vấn tin tức Thạch Nghị, biết thêm việc Võ Vương đã xuất quan và có Chí Cường Giả hộ pháp cho Thạch Nghị khi mở Động Thiên thứ mười. Hắn đi tới Diễn Võ Trường, tìm dấu vết cha mình nhưng thấy riêng thế hệ Thạch Tử Lăng bị thiếu hụt, sau đó chạm vào kỷ lục bia của Thạch Nghị. Chí Tôn Cốt trong ngực Nhóc Tỳ phát sinh cảm ứng khiến tấm bia thiên thạch khắc chưởng ấn Thạch Nghị nổ tung chia năm xẻ bảy. Người Võ Vương Phủ lập tức kích hoạt cấm trận thượng cổ vây hắn ở trung tâm và gọi cường giả từ thế giới hiện thực sang. Cuối chương, tông lão Thạch Lạp xuất hiện chỉ trích Nhóc Tỳ, và hắn nhận ra đây chính là kẻ năm xưa từng bao che mẹ con Thạch Nghị, kêu người vây giết cha mình."},{"chuong":230,"tieuDe":"Đơn Giản Và Trực Tiếp","tomTat":"Thạch Lạp nghe tin Hùng Hài Tử đến Võ Vương Phủ liền chạy tới quan sát và nhanh chóng nảy sát ý, vì cho rằng thiếu niên này sẽ trở thành kình địch của Thạch Nghị. Bất chấp lời can gián của các trưởng lão, hắn vu cho Nhóc Tỳ xâm phạm tôn nghiêm vương hầu rồi phát động trận pháp Tế Linh Thượng Cổ do Tế Linh Thạch Quốc lưu lại. Nhóc Tỳ không né tránh mà mở mười tòa Động Thiên, để chúng giao hòa thành thần hoàn, che lấp tầm nhìn đối thủ và trực tiếp nghiền nát phù văn cùng trận văn dưới đất. Đại trận Thượng Cổ cạn thần lực, bị phá giải ngay trước mắt mọi người. Nhóc Tỳ nhận ra đám người theo Thạch Lạp là những kẻ thuộc một chi cũ từng bảo vệ mẹ con Thạch Nghị và vây công Thạch Tử Lăng năm xưa. Nó kéo Thạch Lạp về dưới chân, rút Diệt Hồn Châm rồi lại cất đi vì cho là lãng phí, đồng thời bộc lộ ý định ngày sau đến Võ Vương Phủ trong thế giới hiện thực để nói Thạch Hạo còn sống và đánh bại kẻ chiếm Chí Tôn Cốt. Cuối cùng Nhóc Tỳ đạp chết Thạch Lạp, rồi dùng phù văn màu vàng khiến toàn bộ nhân mã của hắn nổ tung thành sương máu."},{"chuong":231,"tieuDe":"Bố Trí Ổn Thỏa","tomTat":"Sau khi một cước đạp chết trưởng bối Thạch Lạp của Võ Vương Phủ trong Hư Thần Giới, Nhóc Tỳ rời tịnh thổ khiến con cháu Thạch Tộc kinh hãi lùi tránh, cường giả tới cứu viện cũng bị trưởng lão ngăn không cho la hét. Người Võ Vương Phủ hé lộ bí mật phong ba năm đó về một Chí Tôn trời sinh đã tàn lụi quá sớm, liên quan vợ chồng Thạch Tử Lăng mà phủ nợ lớn. Nhóc Tỳ trở về Thạch Thôn qua Liễu Thần ở phế tích Hỗn Độn, quyết tâm tu hành đợi tin Thần Sơn Thái Cổ để tìm bảo thuật Côn Bằng. Thạch Thôn sau mấy tháng biến hóa lớn thành vùng tịnh thổ nhờ linh dược, cây đào bạc và trứng thần của Bát Trân Kê. Do con của Đại Tráng gọi cậu bằng thúc thúc, Thạch Phi Giao và Thạch Lâm Hổ cùng tộc trưởng tán thành đổi cách gọi từ Nhóc Tỳ sang tên thật Thạch Hạo. Thạch Hạo diệt đám giặc cỏ cứu một thôn nhỏ cách hai ngàn dặm và phát hiện âm mưu Tiểu Tây Thiên thu thập hắc kim để mở bảo tàng Chí Tôn. Liễu Thần ở lại chờ một sinh linh quen thuộc, trao cành cây óng ánh làm phương tiện cứu viện. Cuối cùng Thạch Hạo đột phá Hóa Linh Cảnh ở tuổi mười một và đồng ý lên đường ra biển tìm bảo thuật Côn Bằng."},{"chuong":232,"tieuDe":"Thiên Thần Sơn","tomTat":"Sau khi thảo luận, Thạch Hạo quyết định ra biển cùng đám thần bộc tìm bảo thuật Côn Bằng, nhưng nhất quyết không tiết lộ vị trí Thạch Thôn vì đó là nơi ký gửi tâm linh tối trọng yếu. Nó cầu viện Liễu Thần, được thân cây cháy đen sảng khoái đáp ứng mở thông đạo dịch chuyển để khỏi lặn lội một hai năm. Cả thôn tiễn biệt lưu luyến, nhiều người rơi lệ; Đại Hồng Điểu muốn theo nhưng bị từ chối, Nhị Ngốc Tử lắc đầu không đi vì dường như có quan hệ ẩn với Thái Cổ Thần Sơn. Vào phút chót Mao Cầu hóa vệt kim quang nhảy lên vai đòi theo và được mang cùng, rồi Thạch Hạo vọt vào thông đạo biến mất. Nó xuất hiện ở vùng thần thổ linh khí đậm đặc, thấy Thái Cổ Thần Sơn chọc thủng mây xanh, và gặp lại thần bộc Hoàng Kim Thú từng bị nó đánh bại ở Hư Thần Giới. Thần bộc dùng uy thế áp nhưng bị mười Động Thiên ngăn, buộc phải cầu cạnh Thạch Hạo mở thông đạo cấm kỵ Côn Bằng, còn tỏa bảo quang tạo cầu thần dẫn đường và hứa tặng bát trân Thái Cổ. Thạch Hạo lao ra định bắt Bát Trân Kê thì bị ngăn, rồi xung đột với thiếu niên tóc xanh khiến nhóm thiếu niên thiếu nữ các thế lực xuất hiện; thiếu nữ áo tím Vân Hi ngăn cản, còn Thạch Hạo thì thầm chê các thiếu nữ mập khiến thiếu nữ tóc bạc Ngân Tuyết hỏi lại và Vân Hi tức giận."},{"chuong":233,"tieuDe":"Xung Đột Và Cường Thế","tomTat":"Thạch Hạo đối đáp trêu chọc nhóm thiếu nữ Thần Sơn, buột miệng chê các nàng mập vì tẩm bổ linh dược nhiều, rồi nhắc lại chuyện từng đánh nhau lăn lộn với thiếu nữ áo tím ở Bách Đoạn Sơn khiến nàng ngại mất mặt. Thiếu niên tóc xanh cảnh cáo về quy tắc Thái Cổ Thần Sơn, bị Thạch Hạo phản bác rằng chính họ cầu cạnh mời hắn tới nên phải kính nể hắn. Thiếu niên tóc dài màu tím đứng ra hòa giải, nhấn mạnh cần đồng tâm hiệp lực để đoạt bảo thuật Côn Bằng khi vào Hải Vực. Nhóm người lên Thiên Thần Sơn cảnh sắc như tiên cảnh, Nhóc Tỳ ngắt linh dược khe núi cho Mao Cầu ăn. Trước Thiên Cung, liên minh các thế lực bàn kế hoạch thu hoạch trong Hải Vực, dùng các thiếu niên Hóa Linh Cảnh làm chủ lực. Có người nghi ngờ Thạch Hạo quá yếu, một thiếu niên mười sáu mười bảy tuổi đã vào Hóa Linh Cảnh hai năm đứng lên thử sức. Thạch Hạo nổi giận, mở đồng thời mười Động Thiên thành vòng thần hoàn nghiền nát tiên hạc rồi một chưởng chia thây đối thủ, khiến cả Thần Sơn khiếp sợ; thiếu niên tóc xanh định động thủ thì một ông lão cao cao tại thượng lên tiếng can ngăn."},{"chuong":234,"tieuDe":"Bắc Hải","tomTat":"Nhóm Chí Cường Giả ngồi trước thiên cung cười xòa hóa giải vụ Thạch Hạo giết người trên Thần Sơn, coi như chuyện nhỏ. Họ cho biết vì đã vượt Hóa Linh Cảnh nên không vào được hang ổ Côn Bằng, có ước hẹn không ra tay mà giao cho hậu bối tranh đoạt bảo thuật Côn Bằng. Tổ phụ thiếu nữ áo tím mở thông đạo năm màu; bị Thạch Hạo trêu tức nên thổi cuồng phong đẩy nó vào, chỉ thét được ba chữ Hùng Hài Tử. Đại quân sáu bảy trăm người xuất hiện ngoài biển cách Thần Sơn mấy trăm vạn dặm — đây là Bắc Hải, cực Bắc của Hoang Vực, khiến Thạch Hạo lần đầu thấy biển mà chấn động. Lão bộc dùng bảo thuyền hạt cây vượt biển nhưng bị quái ngư bạc phóng lôi đình đánh nổ, tử thương hơn nửa; thần bộc dùng da thú che chở và trấn áp quái ngư đến trọng thương. Đoàn tiếp tục bị đàn Hải Ma mấy vạn con và đại trận phong cấm dưới đáy biển vây, phải thổi cổ bảo Thần Sơn phá phù văn mở đường trốn. Cuối cùng gặp Thánh Giả không đầu thời Thượng Cổ cưỡi ngựa đen cầm chiến mâu vàng chém tan da thú, thần bộc nhận ra không thể chống lại và nghi đoàn đã tới Ma Hải gần cổ sào Côn Bằng; Thạch Hạo chấn động thấy cường giả trong biển còn nguy hiểm hơn cả Đại Hoang."},{"chuong":235,"tieuDe":"Vùng Đất Tử Vong","tomTat":"Đoàn hơn ba trăm sinh linh từ Thần Sơn Thái Cổ trên đường tới sào huyệt Côn Bằng bị một Thánh Giả không đầu Thượng Cổ — kỵ sĩ cưỡi ngựa đen cầm chiến mâu vàng óng — thảm sát, chỉ cần chiến mâu quẹt qua là nổ tung. Vài thần bộc thổi sừng thú chí bảo tạo gợn sóng bạc mới tránh được kiếp nạn, còn Thạch Hạo (Hùng Hài Tử) nhận ra kỵ sĩ chỉ có chiến ý không ý thức nên dùng Long Giao Tiễn thoát ly chiến trường. Hơn ba trăm người chỉ còn hơn năm mươi, trong đó có Ngân Tuyết, Xích Hỏa và Thanh Vân, tất cả quyết đoạt bảo thuật Côn Bằng — thần thông cái thế của Thập Hung. Đoàn vượt phong cấm của Giao tôn giả, đánh tan hơn vạn cá mập bạc để tiến vào vùng biển tử vong nơi di địa Côn Bằng chồng lên chiến trường Thượng Cổ. Càng vào sâu tu vi càng bị áp chế bất ổn, thần bộc suy diễn phong ấn thần sào Côn Bằng đang mở và có thể xuất thế hoàn toàn — điều khiến Thạch Hạo cảm thấy bất lợi cho mình. Khi phát hiện mảnh vỡ chiến thuyền Nam Vẫn Thần Sơn và các U Linh Thuyền lạc từ Thượng Cổ, một quái vật xúc tu khổng lồ tấn công; cánh Côn Bằng của Thạch Hạo tự bùng phát cứu nó nhưng nó bị đoàn bỏ mặc, chìm vào biển sâu rồi cuối cùng đạp nước xông thẳng lên một chiếc U Linh Thuyền."},{"chuong":236,"tieuDe":"Câu Đố Còn Sót Lại Từ Thượng Cổ","tomTat":"Bị con bạch tuộc khổng lồ tám tua truy kích, Thạch Hạo buộc phải leo lên U Linh Thuyền — thứ đại biểu cho cái chết — để giữ mạng, trong khi bạch tuộc quay sang cướp luyện chiếc sừng thú chở nhóm thần bộc. Sừng thú phát sáng chặt đứt tua bạch tuộc rồi bay lên trời thoát vùng biển tử vong, nhưng chấn động khiến hơn mười mấy người rớt xuống bị xúc tu tiêu hóa cả xương. Dù thiếu nữ áo tím và Ngân Tuyết đòi cứu Thạch Hạo, Thạch Vân vẫn cười lạnh ném khối xương thú nổ tung vào thuyền rồi cả nhóm bỏ đi. Khoang thuyền tỏa sáng đen giam giữ Thạch Hạo và Bóng Lông, hút tinh khí; hắn vận kiếm gãy khiến vết máu đen trên thân hóa đỏ tươi như thức tỉnh, điên cuồng nuốt sức mạnh U Linh Thuyền và giải phóng cả hai. Thuyền tan rã thu nhỏ còn hơn một trượng, lộ chân tướng là thuyền giấy màu đen khắc dòng chữ Chỉ còn sót lại chính ta thôi cùng dấu vân tay máu của một cô gái Thượng Cổ. Thạch Hạo thu phục thêm một U Linh Thuyền thứ hai làm lá chắn rồi tiến sâu vào biển cấm, cuối cùng thấy hòn đảo tổ chim khổng lồ hơn Ma Sơn Thái Cổ với từng tia Hỗn Độn Khí buông xuống."},{"chuong":237,"tieuDe":"Máu Nhuộm Biển Xanh","tomTat":"Hang ổ Côn Bằng của Thập Hung Thái Cổ xuất hiện trên biển, kéo tinh anh các tộc và nhiều cường giả tới tranh đoạt bảo thuật vô thượng, khiến mặt biển nhuộm đỏ máu. Chim loan xanh và Thiểm Điện Khuyển đại chiến vì thù con cháu, nhưng cả hai trọng thương rồi bị đàn Hải Ma vây giết giữa vùng biển bị gợn sóng cấm kỵ áp chế tu vi. Cửu Linh Vương và các cường giả khác phản kích, song sự nguy hiểm của biển cấm khiến nhiều kẻ phải rút lui. Giao tôn giả hiện thân như dãy núi xám, Thôn Thiên Tước cũng lộ diện chưa chết, rồi bị Hôi Giao đánh để tranh độc chiếm bảo thuật. Khi vách đá cổ phát ra gợn sóng vàng áp chế, Thôn Thiên Tước và Hôi Giao đều rời đi, còn Thạch Hạo nhận ra Hoang Vực sắp bước vào đại loạn. Sau nhiều ngày chém giết, con đường đá mênh mông dẫn tới vùng đất cổ Côn Bằng hiện ra trên biển. Thạch Hạo chờ áp chế hoàn toàn hình thành rồi bỏ U Linh Thuyền, bước lên thềm đá tiến vào đảo. Gần vùng đất cổ, hắn chạm mặt nhóm liên minh Thiên Thần Sơn gồm Vân Hi, Ngân Tuyết, Xích Hỏa, Thanh Vân và thần bộc, những kẻ từng đẩy hắn vào chỗ chết."},{"chuong":238,"tieuDe":"Xé Đôi","tomTat":"Sau khi sống sót thoát khỏi U Linh Thuyền, Thạch Hạo tái ngộ nhóm thiếu nữ áo tím Vân Hi và Ngân Tuyết muốn lôi kéo hợp tác trở lại, nhưng hắn tuyên bố chỉ hứng thú với thuần huyết của Thanh Vân và muốn giết. Thanh Vân kiêu ngạo ra lệnh cho lão bộc di chủng bắt người, đồng thời tiết lộ tin đồn sào huyệt Côn Bằng tự động mở ra không cần thủ đoạn đặc biệt. Lão bộc hóa Toan Nghê tấn công bằng lôi hải, nhưng Thạch Hạo áp sát nhờ đôi cánh Côn Bằng, kéo gãy cánh tay và phá xương cốt, dùng phù văn Nguyên Thủy Chân Giải hóa giải cốt văn nên không bị thương. Thanh Vân là sinh linh thuần huyết mở chín Động Thiên, hóa thành chim Thanh Loan thi triển vạn kiếm và thần thông thiên phú hai dải ngân hà giam cầm cố định Thạch Hạo. Thạch Hạo bùng phát mười tòa Động Thiên cùng xuất hiện nối liền thành vòng thần hoàn bất hủ ẩn thần lực Hóa Linh, phá tan hai dải ngân hà thoát giam cầm khiến mọi người kinh ngạc. Cuối cùng hắn bắt cổ chân Thanh Vân đập xuống thềm đá di tích Thượng Cổ làm biến dạng mặt, rồi ôm chân đạp kéo xé rách hai chân hắn hơn phân nửa."},{"chuong":239,"tieuDe":"Hang Ổ Thật Sự","tomTat":"Thạch Hạo trong trạng thái Hóa Linh Cảnh với Mười Động Thiên dung hợp đánh Thanh Vân trọng thương, khiến xương cốt đối thủ đứt gãy nghiêm trọng, nhưng phù văn của đám thần bộc bảo vệ Thanh Vân nên hắn không chết. Khi thần bộc định bắt Thạch Hạo, đàn Hỏa Viêm Ngư trong truyền thuyết bất ngờ xuất hiện như dòng lũ lửa, làm hỗn loạn thềm đá và giúp Thạch Hạo thoát khỏi nguy cơ. Thanh Vân vừa đau đớn vừa uất hận, thề sau khi hồi phục sẽ tự tay giết Thạch Hạo, còn Thạch Hạo chế nhạo hắn đã không còn hy vọng nếu không có người cứu. Sau nhiều ngày leo lên đỉnh đảo, Thạch Hạo phát hiện hang ổ Côn Bằng ở đó đã biến mất, chỉ còn Hỗn Độn Khí và một tòa trận pháp truyền tống Thái Cổ. Cổ trận đưa mọi người rời xa bảy tám mươi vạn dặm tới vùng đất cổ có linh khí Tiên Thiên đậm đặc, nơi hang ổ thật của Côn Bằng nằm trên rặng đá ngầm giữa biển. Sinh linh các phương chém giết đẫm máu để tranh đường vào, trong đó một hậu nhân Hải Thần mặc chiến y vàng dùng Tam Xoa Kích giết sạch đám người cãi lời. Cuối chương, Thạch Hạo chú ý tới cánh cửa vàng rực rỡ như nối liền Thần Giới và kinh ngạc khi thấy một chiếc thuyền giấy màu đen trôi ra từ bên trong."},{"chuong":240,"tieuDe":"Phiêu Lưu Vạn Cổ","tomTat":"Thạch Hạo thu lấy một chiếc thuyền giấy màu đen trôi trên dòng sông linh dịch, nghi ngờ nó liên quan đến hình dáng nguyên thủy của U Linh Thuyền. Trên thuyền có dòng chữ máu “Chỉ còn lại mỗi mình ta”, vết máu vẫn đỏ tươi và ẩn chứa thần năng mênh mông, khiến hắn cảm nhận cảnh tượng nhật nguyệt tinh hà đảo lộn như đến từ vạn cổ. Ngay sau đó, quần hùng phát hiện Côn Mộc trong cánh cửa cấm kỵ, gồm một khúc gỗ mục có long văn, thánh huy cùng chiếc lá trong suốt không mục nát, làm vô số sinh linh điên cuồng lao vào tranh đoạt. Dòng sông trước cửa lại là vùng cấm đáng sợ, bất kỳ ai bước vào đều nổ tung thành tro bụi, kể cả sinh linh biển khổng lồ. Hậu nhân Hải Thần xuất hiện trong chiến y hoàng kim, dùng sóng biển vàng và chiến kích quét ngang, nghiền nát nhiều cường giả để uy hiếp quần hùng. Khi thuộc hạ Hải Tộc khiêu khích và định đạp vào ngực Thạch Hạo, hắn dùng kiếm gãy màu đen chém đôi đối phương. Hậu nhân Hải Thần tức giận chỉ kích về phía hắn, còn Thạch Hạo đáp trả rằng dù là Hải Thần nếu dám trêu chọc hắn cũng chỉ có con đường chết."},{"chuong":241,"tieuDe":"Hậu Nhân Hải Thần","tomTat":"Hậu nhân Hải Thần xuất hiện với chiến kích màu vàng, ép Thạch Hạo giao chiến để báo thù cho người hầu bị giết, khí thế được xưng như Hải Thần thiếu niên tái thế. Thạch Hạo vận dụng mười Động Thiên nối thành vòng thần hoàn, tạo sức giam cầm kinh người rồi dùng kiếm gãy chém xuống, nhưng đối thủ vẫn phá thế mà đứng vững, khiến quần hùng chấn động. Khi hai bên đang đối đầu, một thiếu niên tóc đỏ do Hỏa Viêm Ngư hóa hình lao tới, cầm chiến mâu màu máu tấn công hậu nhân Hải Thần, khơi lại mối thù xưa giữa tộc Hỏa Viêm Ngư và Hải Thần nhất mạch. Hai cường giả trẻ tuổi giao chiến dữ dội, còn Thạch Hạo nhân cơ hội rút khỏi vòng xoáy, chạy về phía hang ổ Côn Bằng, đồng thời cảm nhận cốt văn màu vàng trong cơ thể sôi trào bất thường khiến nó sinh cảnh giác. Tại hang ổ Côn Bằng, các cường giả lục địa dùng một mảnh tàn cốt Côn Bằng để phá phong ấn lối vào, khiến sương mù hỗn độn tràn ra và đạo trường cổ xưa rung chuyển. Lối vào vừa hé mở, quần hùng lập tức đồng loạt xông lên tranh đoạt bảo thuật, còn Thạch Hạo chạy tới chứng kiến cảnh hỗn loạn ấy thì nhíu mày vì cục diện đã biến đổi quá nhanh và quá khó lường."},{"chuong":242,"tieuDe":"Hỗn Chiến","tomTat":"Trước cổ sào Côn Bằng, quần hùng từ nhiều chủng tộc lao vào chém giết để tranh đoạt bảo thuật, thi thể chất đống và máu chảy thành sông. Thạch Hạo lẫn trong đám đông tiến sát lối vào, bị một hải thú trắng bạc cầm búa lớn ngăn cản nhưng dùng kiếm gãy chém đứt đôi cây búa rồi lọt vào trong. Bên trong là đạo tràng thời Thái Cổ rộng lớn, tự thành một giới, nơi tu vi vượt Hóa Linh bị áp chế và có tảng đá khắc huyền cơ về Côn Bằng. Tử Tinh Ngư xuất hiện với Tử Tinh Kiếm, phun khí tím hóa thành vầng mặt trời tím càn quét cường giả, phá hủy bức tranh trên tảng đá rồi hút đá vụn. Thanh Vân thương thế đã khỏi, cầm kim tiên truy sát Hùng Hài Tử để rửa nhục, nhưng bị Thạch Hạo nhắc lại chuyện từng bị xé hai chân khiến thế công rối loạn. Thần bộc Thái Cổ Thần Sơn dùng sừng thú chí bảo tạo sóng bạc trói ánh kiếm, rồi giao chiến khiến Thạch Hạo dù hiện thập đại Động Thiên vẫn bị chấn lùi vì tu vi còn thấp. Khi có tiếng hô đã tới phần cuối, toàn bộ hỗn chiến tạm dừng, mọi người chen lấn lao về phía trước."},{"chuong":243,"tieuDe":"Tỉnh Ngộ","tomTat":"Con đường duy nhất vào trung tâm hang ổ Côn Bằng bị một đôi cửa đá khổng lồ và cổ mộc ngăn lại, khiến quần hùng nhận ra đây mới là lối vào chân chính. Hải Kình, Bạo Viên bạc cùng nhiều sinh linh thử phá cửa, nhưng phù văn trên cửa đá bùng nổ thành đại sát kiếp, giết chết tối thiểu ba phần mười người có mặt; Thạch Hạo nhờ kiếm gãy hộ thể nên chỉ bị chấn thương, không nguy hiểm tính mạng. Sau đó các thế lực gộp máu, cốt, vảy và lông Côn Bằng, khiến cửa đá chấp thuận mở ra, để mọi người tràn vào đạo tràng đầy linh dược và bảo dược. Dù bảo địa hấp dẫn, phần lớn cường giả vẫn tiếp tục tiến sâu vì bảo thuật Côn Bằng còn ở nơi xa hơn, còn hành trình kéo dài hơn một tháng vẫn chưa tới điểm cuối. Thạch Hạo trong quá trình ấy nhận ra chấp niệm tranh đoạt bảo thuật đã khiến đạo tâm bất ổn và bản thân liên tục lao vào đại chiến nguy hiểm. Cậu quyết định dừng tranh cướp, chọn tĩnh tâm tu luyện trên cổ mộc trong hang ổ; khi ngộ pháp, mười Động Thiên hiện lên, hai tòa Côn Bằng và Toan Nghê tỏa khí lành, biểu hiện sự lột xác ở Hóa Linh Cảnh."},{"chuong":244,"tieuDe":"Thân Thể Thành Linh","tomTat":"Thạch Hạo ngồi ngộ đạo trong Hóa Linh Cảnh tại hang ổ Côn Bằng, xương trán phát sáng, thần thức căng trào, thân thể dần hóa linh từ huyết nhục đến xương cốt. Những thương thế do các trận đại chiến trước đó được chữa lành, lục phủ ngũ tạng trở nên óng ánh, khí tức tăng mạnh qua quá trình thôn hà thổ tụy. Chương giải thích thân thể thành linh là bước lớn đầu tiên và là căn cơ quan trọng nhất của Hóa Linh Cảnh, trước khi tinh thần đắp nặn chân ngã và dưỡng linh với thập đại Động Thiên. Mao Cầu tỉnh lại sau lột xác, ăn rất nhiều linh dược trong vùng đất cấm và kéo về tám tấm bia đá Côn Bằng ghi tiểu sử khổ tu của Côn Bằng. Thạch Hạo cùng Mao Cầu rời hang ổ, trong khi nhiều thế lực bên ngoài đã lui dần vì tử thương mà không tìm ra bảo thuật. Sau đó Thạch Hạo xuống biển, lần lượt mài giũa thân thể tại động Cực Dương, vực Huyền Băng và mộ Vẫn Tinh. Gần ba tháng sau, ở đáy biển tối tăm, nó mở mắt bắn ra điện thần và xác nhận thân thể thành linh đã thành công."},{"chuong":245,"tieuDe":"Con Đường Chân Chính","tomTat":"Sau ba tháng mài giũa dưới đáy biển, Thạch Hạo đạt tới thân thể thành Linh, toàn thân lột xác tới cực điểm và bước vào trạng thái trong ngoài như một. Nó dựa vào Nguyên Thủy Chân Giải do Liễu Thần từng mang tới Thạch Thôn để tổ hợp phù văn trong cơ thể, khiến giai đoạn Hóa Linh Cảnh này viên mãn và chiến lực tăng vọt. Khi trở lên mặt biển, Thạch Hạo thấy vùng gần hang ổ Côn Bằng vẫn tranh đoạt dữ dội, nhiều tu sĩ và cường giả ẩn thân tụ tập. Nó phát hiện hang ổ Côn Bằng phóng ra phù văn nguyên thủy không trọn vẹn, từ đó ngộ ra con đường vô hình dẫn tới bảo thuật Côn Bằng chỉ dành cho người đi đúng con đường tu hành ấy. Trong nửa tháng tiếp theo, mỗi ngày nó đều thu hoạch pháp môn đơn giản từ biến hóa phù văn, dù chưa nắm được bảo thuật chân chính. Cuối chương, Thanh Vân dẫn cao thủ vây Thạch Hạo; Thạch Hạo không còn nhẫn nhịn, quyết định lấy sinh linh thuần huyết này làm đối tượng thử sức sau khi thân thể thành Linh."},{"chuong":246,"tieuDe":"Vô Đề","tomTat":"Thanh Vân, người kế thừa Thái Cổ Thần Sơn, nổi giận vì từng bị Thạch Hạo làm nhục và đích thân cầm kim tiên tiến lên đối phó. Thạch Hạo không né tránh, tay không đón đánh, dùng lực lượng Toan Nghê và thân thể cường hoành liên tục nện đến mức kim tiên cong vẹo rồi vỡ tung, khiến các thần bộc nghi hắn đã đạt trạng thái Thân thể thành linh. Thanh Vân hóa bản thể Thanh Loan, dùng phù văn xanh như sao lớn công kích nhưng vẫn bị Thạch Hạo luyện hóa và áp chế. Khi tứ đại thần bộc chia bốn hướng đánh úp, Đả Thần Thạch và Kiến gãy cùng xuất hiện, còn Thập đại Động Thiên của Thạch Hạo liên kết thành thần hoàn chấn Thanh Loan phun máu. Thạch Hạo cưỡi lên lưng Thanh Loan, bẻ gãy cổ giết chết Thanh Vân bất chấp lời khuyên nể mặt Thái Cổ Thần Sơn; sức mạnh cấm kỵ trong thân Thanh Loan tự hủy, làm hắn không đoạt được bảo thuật bộ tộc. Vân Hi và Ngân Tuyết chứng kiến cảnh này trong kinh hãi, còn Thạch Hạo thu xác Thanh Loan rồi rời xuống biển sâu. Sau đó hắn lấy U Linh Thuyền làm thuyền ngắm biển, ăn thịt Thanh Loan, uống rượu Hầu Nhi với Mao Cầu, rồi gặp một mỹ nhân bí ẩn đạp sóng lên thuyền để kết thiện duyên."},{"chuong":247,"tieuDe":"Đối Thủ Xinh Đẹp","tomTat":"Trên U Linh Thuyền, Thạch Hạo gặp một thiếu nữ áo đen cực kỳ xinh đẹp âm thầm bước lên thuyền, khiến hắn lần đầu không nhìn thấu đối phương và lập tức cảnh giác. Nàng lấy Túi Càn Khôn tinh xảo ra bày rượu thịt, vừa tự nhiên đòi uống rượu vừa lộ ý cướp đoạt, còn Thạch Hạo cũng nảy ý cướp túi của nàng. Khi Thạch Hạo vận Thập đại Động Thiên thành thần hoàn ép tới, thiếu nữ hóa thành màn mưa ánh sáng rồi hợp lại, làm hắn và Mao Cầu kinh ngạc. Sau đó hai người cùng ăn thịt Thanh Loan thuần huyết và uống Hầu Nhi Tửu đến nửa đêm; thiếu nữ ăn còn nhanh hơn Thạch Hạo, trong khi hắn nhân dịp vừa đột phá để củng cố cảnh giới. Thiếu nữ tiết lộ mình không phải người Hoang Vực, đến vì Côn Bằng nhưng thấy độ khó quá lớn nên muốn trộm cắp trước, đồng thời cảnh báo Hoang Vực sau này sẽ rất loạn. Cuối chương, hai người bàn kế đánh lén các cường giả như người của Thần Sơn, hậu nhân Hải Thần và thiếu niên Hỏa Viêm Ngư, rồi quyết định bắt đầu một trận Thánh Chiến cướp bóc."},{"chuong":248,"tieuDe":"Thánh Chiến","tomTat":"Thạch Hạo cùng thiếu nữ đạp biển tiến về hang ổ Côn Bằng, ban đầu bàn chuyện cướp Tam Xoa Kích của hậu nhân Hải Thần và viêm trấp thần tính của bộ tộc Hỏa Viêm Ngư. Khi phát hiện Hải Tộc dựng tế đàn lớn đối diện rặng đá ngầm để hậu nhân Hải Thần cảm ngộ bí pháp Côn Bằng, thiếu nữ đổi mục tiêu sang đoạt Côn Bằng pháp trong đầu hắn bằng cổ pháp đọc tâm tư. Nàng nhận ra Đả Thần Thạch trên tóc Thạch Hạo, truyền cho hắn thần chú khống chế khiến Đả Thần Thạch phải nghe lời và tăng uy lực. Sau mấy ngày chờ đợi, Thạch Hạo trà trộn vào đám cu li, dùng Đả Thần Thạch nện trúng trán hậu nhân Hải Thần; thiếu nữ nhân cơ hội thi triển cổ pháp nhưng thất bại vì đối phương quá mạnh. Dù không đọc được tâm tư, hai người vẫn lấy được tàn cốt Côn Bằng và miếng vảy, còn hậu nhân Hải Thần sau khi tỉnh lại bạo nộ chém giết các kẻ hôi của. Thiếu nữ tiết lộ thân thể hiện tại chỉ là Linh Thân được nuôi dưỡng từ một Động Thiên, chân thân đang vướng chuyện nên khó vào Hoang Vực. Hai người tiếp tục nhiều ngày cướp bóc cường giả vùng biển bằng Đả Thần Thạch, thậm chí suýt thất thủ trước lão giao màu xám nghi là Linh Thân của Tôn Giả. Cuối cùng thiếu nữ rời đi vì tinh lực phân tán sẽ nguy hiểm cho chân thân, Thạch Hạo hẹn sau này cùng đi Thái Cổ Thần Sơn và Hải Thần Đảo, rồi thời gian lướt qua hai năm."},{"chuong":249,"tieuDe":"Đắp Lại Chân Ngã","tomTat":"Hai năm sau biến cố ở vùng biển Côn Bằng, quần hùng vẫn ra vào tranh đoạt, vô số sinh linh chết trận nhưng thần sào và bảo thuật chân kinh Côn Bằng vẫn chưa ai phá được. Chuyện Giao Tôn Giả bị hai tên trộm cướp sạch truyền ra ngoài, khiến hắn mất mặt và sai con cháu Giao Tộc lùng bắt, trong khi Thạch Hạo còn bí mật đánh mười tám cháu trai của hắn để cảnh cáo. Thạch Hạo lúc này hơn mười ba tuổi, thân mang mười Động Thiên và đã tu tới đỉnh cao Hóa Linh Cảnh, vượt xa nhiều thiên tài thuần huyết như Thanh Vân. Hắn ngồi dưới đáy biển trong Động Cực Dương, dùng chân hỏa dương cương cực điểm thiêu luyện thân thể và tinh thần nguyên, khiến da thịt nhiều lần cháy đen rồi tái sinh. Sau đó hắn chuyển sang Vực Huyền Băng, chịu chí hàn làm tinh thần nguyên đông kết, vỡ tan rồi khôi phục, luân phiên giữa hai cực dương và hàn. Cuối cùng Thạch Hạo hoàn thành giai đoạn Đắp lại chân ngã trong Hóa Linh Cảnh tới viên mãn, cạnh thân hiện lên Côn Bằng và Toan Nghê rít gào cộng hưởng như có linh tính."},{"chuong":250,"tieuDe":"Xuất Quan","tomTat":"Thạch Hạo bế quan trong động Cực Dương suốt hai năm, tinh thần sung mãn và lần lượt đẩy Thân thể thành linh cùng Đắp lại chân ngã tới ranh giới trong truyền thuyết, khiến chiến lực tăng vọt. Nó thử tiếp cận bệ đá cấm địa sâu trong động nhưng bị chân hỏa đánh thẳng vào linh hồn, nhận ra mình còn thiếu Hóa Linh Cảnh vô khuyết viên mãn mới có thể đặt chân lên đó. Khi xuất quan, nó biết vùng biển đã biến động dữ dội: nhiều đại nhân vật Hóa Linh Cảnh chết, Tôn Giả xuất thế, các thế lực Hải Tộc và Thần Sơn đều tụ lại. Mạc Thương, hậu nhân Hải Thần, đánh bại Nhân Ngư Tộc và muốn đoạt bảo thuật Côn Bằng để phong Thần, trong khi Hàn Thiên của bộ tộc Hỏa Viêm Ngư cũng là một đối thủ lớn từng cùng hắn lưỡng bại câu thương. Hang ổ Côn Bằng bắt đầu nứt ra, phù văn hiện lên trên rặng đá ngầm, Thạch Hạo đọc được một đám ký hiệu thần bí nhưng chưa rõ ý nghĩa. Khi nó tiến về phía hang ổ, quần hùng nhận ra tên trộm năm xưa; Mạc Thương, Thái Cổ Thần Sơn và Giao Tôn Giả đều lộ địch ý, còn Thạch Hạo thẳng thừng cảnh cáo rằng ai chọc nó sẽ bị ăn sạch."},{"chuong":251,"tieuDe":"Chiến Quần Hùng","tomTat":"Thạch Hạo xuất hiện trước quần hùng với dáng vẻ ngang ngược, lớn tiếng cảnh cáo ai dám trêu chọc sẽ bị ăn sạch, khiến những người từng biết hắn ở Bách Đoạn Sơn và Hư Thần Giới, nhất là Vân Hi, vừa lo lắng vừa kinh ngạc vì nhận ra hắn đã lại đột phá. Khi đám Hải Tộc không biết uy danh hắn mà xông lên, Thạch Hạo chỉ điểm Hải Giao, Ngân Sa Vương, Đại Hải Quy như chọn nguyên liệu, rồi dùng vòng xoáy vàng cuốn các sinh linh mạnh nhất, xuyên thủng mi tâm và thu xác vào Túi Càn Khôn. Mạc Thương, hậu nhân Hải Thần đang thủ trên tế đàn, vung chiến kích tạo cơn lũ vàng nhằm trấn áp nhưng bị Thạch Hạo một quyền phá tan, song hắn vẫn không rời tế đàn vì lo bị điệu hổ ly sơn khỏi lô cốt chiến tranh. Tiếp đó huynh trưởng của Thanh Vân, cường giả trẻ Thái Cổ Thần Sơn và sinh linh thuần huyết, đứng ra đòi mạng Thạch Hạo vì đệ đệ bị giết; lão bộc Thái Cổ Di Chủng xin thay chủ xuất thủ. Thạch Hạo thi triển bảo thuật tự diễn biến, sau lưng hiện đại dương đen và cá lớn do phù văn thai nghén, bị người ngoài nhầm là bảo thuật Côn Bằng nhưng được Tôn Giả nhận ra là khác biệt. Lão bộc bị chấn bay, hóa bản thể vàng lớn như núi liều mạng nhưng tiếp tục bị con cá đen đánh trọng thương gần tắt thở; Thạch Hạo không truy sát, chỉ cảnh cáo đừng chọc vào mình rồi nhìn sang thiếu niên tóc xanh, Mạc Thương và Giao Tôn Giả, khiến cả hải vực lặng đi vì chấn động."},{"chuong":252,"tieuDe":"Thiếu Niên Thiên Kiêu","tomTat":"Trên hải vực, Thạch Hạo bị một nam tử tóc xanh nhất mạch Thanh Loan khiêu chiến. Đối phương là sinh linh thuần huyết của Thái Cổ Thần Sơn, đã mở chín Động Thiên và thi triển thần thông Thanh Loan, nhưng bị Thạch Hạo dùng bảo thuật Toan Nghê diễn hóa lôi hải cùng hai cối xay màu vàng áp chế. Khi nam tử tóc xanh xuất linh thân và nhiều sinh linh thái cổ từ Động Thiên, Thạch Hạo mở mười Động Thiên, hợp thành thần hoàn như thần dương để giam cầm đối thủ, khiến Hải Tộc kinh sợ. Nam tử tóc xanh hóa thành Thanh Loan thoát ra, nhưng Côn Bằng từ Động Thiên Thạch Hạo bay lên chém rơi một cánh, còn Thạch Hạo dùng Túi Càn Khôn thu cánh ấy như nguyên liệu ăn uống. Sau đó Thạch Hạo nhận ra lão giả tóc xám áo bào xám ngoài xa rất có thể là chân thân Giao Tôn Giả, người từng bị nó và ma nữ cướp sạch. Tại tế đàn, Thạch Hạo khiêu khích Mạc Thương, hậu nhân Hải Thần, bằng cách hỏi bản thể hắn ăn có ngon không, rồi hai thiếu niên thiên kiêu quyết chiến ngang tài bằng nhục thân và phù văn. Giữa trận, Côn Bằng Sào trên đảo đá ngầm phát sáng vàng kim, nứt toác dữ dội và sắp hoàn toàn chia năm xẻ bảy."},{"chuong":253,"tieuDe":"Đại Quyết Chiến","tomTat":"Sào huyệt Côn Bằng màu đen khổng lồ mở ra, toàn thân tỏa vàng kim và gây chấn động cả hải vực. Quần hùng, kể cả những người vốn đứng xa quan sát, đều lao tới vì bảo thuật vô thượng, còn các cường giả và Tôn Giả cũng lần lượt hiện thân. Trên tế đàn, Thạch Hạo và Mạc Thương giao chiến dữ dội bằng phù văn, quyền cước và đại kích màu vàng; Mạc Thương dùng binh khí đâm vào ngực đối thủ nhưng bị Thạch Hạo né tránh rồi đánh bật đại kích lên trời. Khi có người định cướp đại kích, Mạc Thương vẫn khống chế được nó, khiến binh khí phóng phù văn và tia chớp vàng giết chết một cao thủ, làm những kẻ khác kinh sợ. Mạc Thương tiếp tục thi triển Hải Thần Nhất Trảm, triệu hồi đại kích, mọc đôi cánh Hải Thần vàng và dùng trạng thái thiên nhân hợp nhất để mượn lực trời đất, trong khi Thạch Hạo dùng mười tòa Động Thiên hóa thần hoàn phong tỏa hư không chống đỡ. Người quan chiến nhận ra Mạc Thương đã Hóa Linh Cảnh viên mãn, còn Thạch Hạo chưa viên mãn nên tưởng cậu sẽ bị đại kích xuyên chết. Nhưng mười Động Thiên của Thạch Hạo tương liên tẩm bổ thành dạng huyết nhục Động Thiên, giữ lại chiến kích mà không làm thân thể bị thương. Thạch Hạo lập tức tung một quyền mạnh mẽ đánh thủng lồng ngực Mạc Thương, làm áo giáp vàng nổ tung và khiến tất cả chấn kinh."},{"chuong":254,"tieuDe":"Thần Tàng Côn Bằng Mở Ra","tomTat":"Thạch Hạo một quyền đấm thủng ngực Mạc Thương, khiến hậu nhân Hải Thần trọng thương và phá vỡ trạng thái thiên nhân hợp nhất của hắn. Mạc Thương dùng dược tán luyện theo đan phương Hải Thần để chữa lành vết thương, khôi phục chiến lực rồi tiếp tục quyết chiến, trong khi Thạch Hạo còn cố ý xem xét khối thịt rơi ra như muốn ăn khiến đám đông kinh ngạc. Giữa lúc hai bên đại chiến, Côn Bằng Sào nổ tung mở ra hoàn toàn, lộ đạo tràng sáng chói, thần âm thái cổ và con đường dẫn vào thần tàng. Đám đông ùa vào tranh đoạt ao thần dịch, Mạc Thương dùng tế đàn sát phạt mở đường, còn Thạch Hạo thu được hơn mười giọt linh hải cuối. Tiến sâu hơn, mọi người phát hiện kim hải trong động phủ, đáy biển có động Côn Bằng chứa thần tàng nên Hàn Thiên, Mạc Thương, Hải tộc và cường giả lục địa cùng lao xuống. Dưới đáy biển, Thạch Hạo dùng mười tòa Động Thiên hợp thành thần hoàn, cầm cố hư không và xoắn nát những kẻ vây công, khiến nhiều Tôn Giả và vương hầu kiêng dè. Ở sâu trong động phủ, hai Tôn Giả tranh đoạt Thần Chiếu Thanh Đồng Đăng nhưng Hàn Thiên bất ngờ cướp đi, còn phù văn Côn Bằng cùng nhiều thái cổ pháp khí và chí bảo lộ ra phía trước, khiến tất cả điên cuồng xông vào."},{"chuong":255,"tieuDe":"Đoạt Bảo","tomTat":"Trong đạo tràng Côn Bằng dưới đáy biển, một cửa đá mở ra để lộ bình ngọc và chén ngọc chứa thần tửu, khiến hơn mười cường giả lao vào tranh đoạt. Mạc Thương cầm chiến kích màu vàng xuất hiện, chấn chết nhiều người rồi giao chiến với Thạch Hạo, nhưng Mao Cầu bất ngờ chui ra cướp bình ngọc, làm phá phong thần tửu trước khi Thạch Hạo thu bình vào Túi Càn Khôn. Ở nơi khác, dược lô Côn Bằng phun sương mù đen kịch độc giết hại nhiều người, Hàn Thiên dùng Thần Chiếu Đăng luyện hóa sạch độc vụ, còn Giao Tôn Giả nhận ra dấu vết Chân Giao bị luyện thành độc tán và lặng lẽ tiềm hành. Trong thạch thất sâu nhất, mọi người phát hiện bảo bình cắm hoa mới là chí bảo Ngọc Tịnh Bình giống vật của Tiểu Tây Thiên, khiến các vương hầu đại chiến tranh giành. Thạch Hạo không tranh bình mà nhắm đến bồ đoàn Côn Bằng, nhận ra nó là vật bện từ rễ cây non xanh biếc, nặng hơn mười vạn cân. Hắn xuất mười tòa Động Thiên chộp bồ đoàn rồi dùng chính bồ đoàn như búa đánh văng đại ấn của lão giả Hóa Linh cảnh, khiến thạch thất chấn động dữ dội."},{"chuong":256,"tieuDe":"Bảo Tàng","tomTat":"Trong động phủ Côn Bằng, bồ đoàn côn mộc và Ngọc Tịnh Bình khiến đám cường giả tranh đoạt dữ dội. Thạch Hạo thúc dục mười tòa Động Thiên hóa thần hoàn, dùng thanh kiếm gãy màu đen chém sạch một đám người rồi thu bồ đoàn vào Túi Càn Khôn, trong khi Ngọc Tịnh Bình bị kẻ khác lấy mất. Tiến sâu vào động phủ, mọi người phát hiện Luyện Binh Địa, nơi có hàn đàm chứa các khí phôi Thái Cổ như kiếm thai Long Cốt Thiết và bảo tháp Hỗn Độn Thổ, nhưng hàn khí thần tính có thể đóng băng người tới gần. Mạc Thương, Hàn Thiên, các Tôn Giả và sinh linh Thái Cổ Thần Sơn cùng lao vào tranh đoạt; Thạch Hạo dùng Đả Thần Thạch, nhờ chú ngữ ma nữ từng dạy, đánh trọng thương nhiều đối thủ. Sau cùng, Thạch Hạo bắt được Linh Lung Tháp Hỗn Độn Thổ, nhưng Cốt Tháp ẩn trên tóc lần đầu lên tiếng, nuốt hơn phân nửa Hỗn Độn Thổ để đổi cho hắn một lần cơ hội cứu mạng. Đả Thần Thạch được phần mảnh vụn còn lại để lột xác. Cuối chương, trời đất chấn động, đại điện phía trước động phủ mở ra và một con Côn Bằng bễ nghễ thế gian xuất hiện trong hỗn độn khí."},{"chuong":257,"tieuDe":"Thiên Hoang","tomTat":"Một tòa điện phủ cổ xưa khổng lồ trong thần sào Côn Bằng mở ra, cửa đá cao mấy vạn trượng hé lộ cảnh tượng như một thế giới riêng. Bên trong hiện ra bóng Côn Bằng sống động, khi hóa đại bàng vàng bay trong trời sao, khi hóa cá lớn màu đen rộng mấy vạn dặm, thần uy ép nhiều sinh linh quỳ xuống. Sau khi dị tượng biến mất, mọi người tiến vào đại điện và phát hiện một tế đàn cổ cao như núi, nơi có linh dược, thác tinh khí và cây Tinh Thần Thảo bảy lá sắp thành thánh dược. Trên tế đàn còn có nhiều binh khí thái cổ, nổi bật nhất là Thiên Hoang, đại kích chí cao Thiên Giai từng theo Côn Bằng chinh chiến, nay đã gãy ba đoạn nhưng vẫn phóng tinh hà đánh bay kẻ tới gần. Không ai, kể cả Tôn Giả, có thể câu thông hay thu lấy các thần binh, nên có người đề nghị phải dâng tàn cốt, lân phiến hoặc lông vũ Côn Bằng để leo lên tế đàn. Thạch Hạo cũng lấy ra một mảnh tàn cốt từng cùng ma nữ cướp từ Mạc Thương, khiến Mạc Thương giận dữ, rồi mọi người nhờ các di cốt mà lên được nơi cao nhất. Cuối chương, ánh mắt tất cả dồn vào bệ đá như quan tài, nơi đặt khối cốt màu vàng xen vân đen, phù văn chằng chịt lưu chuyển áo nghĩa chư thiên."},{"chuong":258,"tieuDe":"Phù Cốt Côn Bằng","tomTat":"Nguyên thủy phù cốt Côn Bằng lộ diện trên bệ đá, tỏa phù văn như ngân hà và hiện pháp tướng Côn Bằng che kín thiên địa, khiến quần hùng kinh hãi. Mọi người phát hiện khối cốt có vết nứt nhưng phù văn bên trong không thiếu, vẫn có thể tham ngộ, nên lòng tham càng bùng lên. Đại hỗn chiến nổ ra, các giáo chủ, Tôn Giả và sinh linh mạnh cùng lao vào tranh đoạt; Thạch Hạo chộp phù cốt lần đầu nhưng bị bảo cốt kháng cự đẩy ra. Mạc Thương dùng đại kích chém chết tông lão Nhân Ngư Tộc, đánh bại thiếu nữ thiên tài của tộc này; Hàn Thiên cầm Thần Chiếu Đăng phóng liệt diễm khiến các giáo chủ tránh lui. Thạch Hạo nổi giận tiến vào trạng thái cuồng bạo, mở mười Động Thiên, dùng đoạn kiếm, bảo thuật Toan Nghê và cánh Côn Bằng độc chiến quần hùng, khiến nhiều Tôn Giả cùng lão tổ hình thành ý định liên thủ diệt nó trước. Cuối chương, Thạch Hạo vận dụng Thân thể thành linh kết hợp Kim Tuyền Ba Văn Công để tiếp nạp phù văn, tinh khí, rồi mượn lực hỗn chiến nhảy về trung tâm bệ đá chộp lấy phù cốt."},{"chuong":259,"tieuDe":"Huyết Chiến Bát Phương","tomTat":"Thạch Hạo trọng thương vẫn tử chiến giữa vòng vây trong Côn Bằng Sào, dùng đoạn kiếm và bảo thuật giết vương hầu Hải tộc cùng nhiều cao thủ. Linh thân Thôn Thiên Tước hiện thân, muốn đoạt bảo thuật Côn Bằng và giết Thạch Hạo, nhưng bị thiếu niên liều mạng chém đứt tay, chặt thân, dẫm dưới chân rồi chặt đầu, khiến linh thân vẫn lạc. Bên ngoài vùng biển cấm, bản thể Thôn Thiên Tước cùng nhiều chí cường giả Hoang Vực tụ tập chờ kết quả tranh đoạt. Thạch Hạo kích phát khối nguyên thủy phù cốt Côn Bằng và phát hiện truyền thừa trong đó chỉ chưa đến một phần ba, không phải bảo thuật chân chính trọn vẹn. Khi Côn Bằng Hóa Ma động mở ra và phù cốt phân thành sáu khối, các cường giả điên cuồng tranh cướp. Thạch Hạo giả bộ sức kiệt, cố ý để Giao Tôn Giả và các lão tổ đánh mình rơi xuống Hóa Ma động, mượn cục diện hỗn loạn để tìm đường thoát thân."},{"chuong":260,"tieuDe":"Giải Thoát","tomTat":"Thạch Hạo trọng thương nhưng vẫn huyết chiến trong Côn Bằng Sào, dùng kiếm gãy và bảo thuật giết vương hầu Hải tộc rồi chống lại đợt tập sát của Mạc Thiên, Hàn Thiên cùng nhiều Tôn Giả. Linh thân Thôn Thiên Tước hiện thân tranh đoạt bảo thuật Côn Bằng, nhưng bị Thạch Hạo liều mạng chém đứt tay, chặt ngang thân, dẫm dưới chân và chặt đầu. Bản thể Thôn Thiên Tước ở cuối biển nổi giận, trong khi nhiều chí cường giả Hoang Vực tụ tập ngoài vùng biển cấm chờ kết quả. Thạch Hạo kích phát khối nguyên thủy phù cốt Côn Bằng và phát hiện truyền thừa trong đó chỉ ghi chưa đến một phần ba bảo thuật chân chính. Khối phù cốt mở ra Côn Bằng Hóa Ma động rồi phân thành sáu khối, khiến mọi người điên cuồng tranh cướp. Thạch Hạo giả bộ kiệt sức để Giao Tôn Giả và các lão tổ đánh mình rơi xuống động, thực chất mượn cục diện thiên băng địa liệt để tìm đường trốn thoát."}];
